import React, { useEffect } from 'react';
import { Outlet, Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { FiHome, FiFileText, FiImage, FiMenu, FiFilm, FiBriefcase, FiSettings, FiMail, FiMessageSquare, FiLogOut, FiExternalLink } from 'react-icons/fi';
import './AdminLayout.css';

const menuItems = [
  { path: '/admin', icon: FiHome, label: 'Dashboard', exact: true },
  { path: '/admin/pages', icon: FiFileText, label: 'Páginas' },
  { path: '/admin/media', icon: FiImage, label: 'Mídia' },
  { path: '/admin/menu', icon: FiMenu, label: 'Menu' },
  { path: '/admin/projects', icon: FiFilm, label: 'Projetos' },
  { path: '/admin/services', icon: FiBriefcase, label: 'Serviços' },
  { path: '/admin/testimonials', icon: FiMessageSquare, label: 'Depoimentos' },
  { path: '/admin/contacts', icon: FiMail, label: 'Contatos' },
  { path: '/admin/settings', icon: FiSettings, label: 'Configurações' },
];

export default function AdminLayout() {
  const { user, loading, isAuthenticated, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    if (!loading && !isAuthenticated) {
      navigate('/admin/login');
    }
  }, [loading, isAuthenticated, navigate]);

  if (loading) return <div className="admin-loading">Carregando...</div>;
  if (!isAuthenticated) return null;

  return (
    <div className="admin">
      <aside className="admin__sidebar">
        <div className="admin__sidebar-header">
          <h2>STORNOWAY</h2>
          <span>Admin Panel</span>
        </div>

        <nav className="admin__nav">
          {menuItems.map(item => (
            <Link
              key={item.path}
              to={item.path}
              className={`admin__nav-item ${
                item.exact
                  ? location.pathname === item.path ? 'admin__nav-item--active' : ''
                  : location.pathname.startsWith(item.path) ? 'admin__nav-item--active' : ''
              }`}
            >
              <item.icon size={18} />
              <span>{item.label}</span>
            </Link>
          ))}
        </nav>

        <div className="admin__sidebar-footer">
          <a href="/" target="_blank" rel="noopener noreferrer" className="admin__nav-item">
            <FiExternalLink size={18} />
            <span>Ver Site</span>
          </a>
          <button onClick={() => { logout(); navigate('/admin/login'); }} className="admin__nav-item admin__logout">
            <FiLogOut size={18} />
            <span>Sair</span>
          </button>
          <div className="admin__user-info">
            <span>{user?.username}</span>
          </div>
        </div>
      </aside>

      <main className="admin__main">
        <Outlet />
      </main>
    </div>
  );
}
