import React, { useState, useEffect, useCallback } from 'react';
import { useDropzone } from 'react-dropzone';
import { toast } from 'react-toastify';
import { FiUpload, FiSearch, FiTrash2, FiImage, FiFilm, FiDownload, FiGrid, FiList, FiFolder } from 'react-icons/fi';
import { mediaAPI } from '../api/api';

export default function MediaManager() {
  const [files, setFiles] = useState([]);
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState('');
  const [folder, setFolder] = useState('');
  const [view, setView] = useState('grid');
  const [loading, setLoading] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [page, setPage] = useState(1);
  const [pagination, setPagination] = useState({});
  const [selected, setSelected] = useState([]);

  const loadMedia = useCallback(async () => {
    setLoading(true);
    try {
      const params = { page, per_page: 30 };
      if (filter) params.type = filter;
      if (search) params.search = search;
      if (folder) params.folder = folder;
      const res = await mediaAPI.getAll(params);
      setFiles(res.data.data || []);
      setPagination(res.data.pagination || {});
    } catch {
      toast.error('Erro ao carregar mídia');
    } finally { setLoading(false); }
  }, [page, filter, search, folder]);

  useEffect(() => { loadMedia(); }, [loadMedia]);

  const onDrop = useCallback(async (acceptedFiles) => {
    setUploading(true);
    try {
      if (acceptedFiles.length === 1) {
        const fd = new FormData();
        fd.append('file', acceptedFiles[0]);
        if (folder) fd.append('folder', folder);
        await mediaAPI.upload(fd);
      } else {
        const fd = new FormData();
        acceptedFiles.forEach(f => fd.append('files[]', f));
        if (folder) fd.append('folder', folder);
        await mediaAPI.uploadMultiple(fd);
      }
      toast.success(`${acceptedFiles.length} arquivo(s) enviado(s)!`);
      loadMedia();
    } catch { toast.error('Erro no upload'); }
    finally { setUploading(false); }
  }, [folder, loadMedia]);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: { 'image/*': [], 'video/*': [] },
    maxSize: 500 * 1024 * 1024
  });

  const deleteSelected = async () => {
    if (!window.confirm(`Excluir ${selected.length} arquivo(s)?`)) return;
    try {
      for (const id of selected) { await mediaAPI.delete(id); }
      toast.success('Arquivos excluídos!');
      setSelected([]);
      loadMedia();
    } catch { toast.error('Erro ao excluir'); }
  };

  const toggleSelect = (id) => {
    setSelected(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  };

  const apiBase = process.env.REACT_APP_API_URL || '/api';
  const getUrl = (f) => f.file_path ? `${apiBase}/uploads/${f.file_path}` : '';
  const getThumb = (f) => f.thumbnail_path ? `${apiBase}/uploads/${f.thumbnail_path}` : getUrl(f);
  const formatSize = (bytes) => {
    if (!bytes) return '';
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024*1024) return (bytes/1024).toFixed(1) + ' KB';
    return (bytes/(1024*1024)).toFixed(1) + ' MB';
  };

  return (
    <div className="media-manager">
      <div className="admin-page-header">
        <h1>Biblioteca de Mídia</h1>
        <div style={{ display: 'flex', gap: 8 }}>
          {selected.length > 0 && (
            <button onClick={deleteSelected} className="admin-btn admin-btn--danger">
              <FiTrash2 size={14} /> Excluir ({selected.length})
            </button>
          )}
        </div>
      </div>

      {/* Upload Zone */}
      <div {...getRootProps()} className={`admin-card mm-drop ${isDragActive ? 'mm-drop--active' : ''}`} style={{ cursor: 'pointer' }}>
        <input {...getInputProps()} />
        <div style={{ textAlign: 'center', padding: 20, color: '#888' }}>
          {uploading ? <p>Enviando...</p> : (
            <p style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8 }}>
              <FiUpload size={20} /> {isDragActive ? 'Solte aqui...' : 'Arraste arquivos ou clique para enviar (máx 500MB)'}
            </p>
          )}
        </div>
      </div>

      {/* Filters */}
      <div className="admin-card" style={{ display: 'flex', gap: 12, alignItems: 'center', flexWrap: 'wrap' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 6, background: '#1a1a2e', border: '1px solid #2a2a3e', borderRadius: 6, padding: '6px 10px', flex: 1, minWidth: 200 }}>
          <FiSearch size={14} color="#888" />
          <input value={search} onChange={e => { setSearch(e.target.value); setPage(1); }} placeholder="Buscar..." style={{ background: 'none', border: 'none', color: '#ccc', outline: 'none', width: '100%', fontSize: 13 }} />
        </div>
        <select value={filter} onChange={e => { setFilter(e.target.value); setPage(1); }} className="admin-input" style={{ width: 'auto' }}>
          <option value="">Todos os tipos</option>
          <option value="image">Imagens</option>
          <option value="video">Vídeos</option>
        </select>
        <input value={folder} onChange={e => { setFolder(e.target.value); setPage(1); }} placeholder="Pasta" className="admin-input" style={{ width: 140 }} />
        <div style={{ display: 'flex', gap: 4 }}>
          <button onClick={() => setView('grid')} className={`admin-btn admin-btn--small ${view === 'grid' ? 'admin-btn--primary' : 'admin-btn--secondary'}`}><FiGrid size={14} /></button>
          <button onClick={() => setView('list')} className={`admin-btn admin-btn--small ${view === 'list' ? 'admin-btn--primary' : 'admin-btn--secondary'}`}><FiList size={14} /></button>
        </div>
      </div>

      {/* Files */}
      {loading ? (
        <div className="admin-card" style={{ textAlign: 'center', padding: 40, color: '#888' }}>Carregando...</div>
      ) : view === 'grid' ? (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(140px, 1fr))', gap: 12 }}>
          {files.map(f => (
            <div key={f.id} onClick={() => toggleSelect(f.id)} className="admin-card" style={{ padding: 0, cursor: 'pointer', overflow: 'hidden', border: selected.includes(f.id) ? '2px solid #c9a96e' : undefined }}>
              <div style={{ aspectRatio: '1', overflow: 'hidden', background: '#1a1a2e', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                {f.file_type === 'image' ? (
                  <img src={getThumb(f)} alt={f.original_name} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                ) : (
                  <FiFilm size={32} color="#666" />
                )}
              </div>
              <div style={{ padding: '6px 8px' }}>
                <p style={{ fontSize: 11, color: '#ccc', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', margin: 0 }}>{f.original_name}</p>
                <p style={{ fontSize: 10, color: '#666', margin: '2px 0 0' }}>{formatSize(f.file_size)}</p>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="admin-card">
          <table className="admin-table">
            <thead><tr><th></th><th>Nome</th><th>Tipo</th><th>Tamanho</th><th>Data</th></tr></thead>
            <tbody>
              {files.map(f => (
                <tr key={f.id} onClick={() => toggleSelect(f.id)} style={{ cursor: 'pointer', background: selected.includes(f.id) ? 'rgba(201,169,110,0.1)' : undefined }}>
                  <td style={{ width: 40 }}>
                    <input type="checkbox" checked={selected.includes(f.id)} onChange={() => toggleSelect(f.id)} style={{ accentColor: '#c9a96e' }} />
                  </td>
                  <td style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                    <div style={{ width: 36, height: 36, borderRadius: 4, overflow: 'hidden', background: '#1a1a2e', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                      {f.file_type === 'image' ? <img src={getThumb(f)} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <FiFilm size={16} color="#666" />}
                    </div>
                    {f.original_name}
                  </td>
                  <td><span className="admin-badge">{f.file_type}</span></td>
                  <td>{formatSize(f.file_size)}</td>
                  <td>{new Date(f.created_at).toLocaleDateString('pt-BR')}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Pagination */}
      {pagination.total_pages > 1 && (
        <div style={{ display: 'flex', justifyContent: 'center', gap: 12, padding: 16, alignItems: 'center' }}>
          <button disabled={page <= 1} onClick={() => setPage(p => p - 1)} className="admin-btn admin-btn--secondary admin-btn--small">Anterior</button>
          <span style={{ color: '#888', fontSize: 13 }}>Página {page} de {pagination.total_pages}</span>
          <button disabled={page >= pagination.total_pages} onClick={() => setPage(p => p + 1)} className="admin-btn admin-btn--secondary admin-btn--small">Próxima</button>
        </div>
      )}
    </div>
  );
}
