import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { pagesAPI } from '../api/api';
import SectionRenderer from '../components/SectionRenderer';

export default function DynamicPage() {
  const { slug } = useParams();
  const [page, setPage] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    pagesAPI.getBySlug(slug)
      .then(r => setPage(r.data.data))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [slug]);

  if (loading) return <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', paddingTop: 80 }}>Carregando...</div>;
  if (!page) return <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', paddingTop: 80, fontFamily: "'Montserrat', sans-serif" }}>Página não encontrada</div>;

  return (
    <div style={{ paddingTop: 80 }}>
      {page.sections?.map(section => (
        <SectionRenderer key={section.id} section={section} />
      ))}
    </div>
  );
}
