import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { useSite } from '../contexts/SiteContext';
import { pagesAPI } from '../api/api';
import SectionRenderer from '../components/SectionRenderer';
import './About.css';

const fadeIn = { hidden: { opacity: 0, y: 30 }, visible: { opacity: 1, y: 0, transition: { duration: 0.8 } } };

export default function About() {
  const { getSetting } = useSite();
  const [page, setPage] = useState(null);

  useEffect(() => {
    pagesAPI.getBySlug('about').then(r => setPage(r.data.data)).catch(() => {});
  }, []);

  return (
    <div className="about-page">
      {/* Hero */}
      <section className="about__hero">
        <div className="about__hero-overlay" />
        <motion.div className="about__hero-content" initial="hidden" animate="visible" variants={fadeIn}>
          <h1 className="about__hero-title">SOBRE</h1>
          <p className="about__hero-subtitle">{getSetting('site_name', 'STORNOWAY')}</p>
        </motion.div>
      </section>

      {/* Seções dinâmicas da página */}
      {page?.sections?.map(section => (
        <SectionRenderer key={section.id} section={section} />
      ))}

      {/* Conteúdo padrão se não houver seções */}
      {(!page?.sections || page.sections.length === 0) && (
        <>
          <motion.section className="about__story" initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
            <div className="about__story-content">
              <h2>NOSSA HISTÓRIA</h2>
              <p>
                Somos um estúdio de cinema dedicado a capturar as mais belas histórias de amor ao redor do mundo.
                Com uma abordagem refinada e cinematográfica, transformamos os momentos mais especiais da sua vida
                em filmes que serão guardados para sempre.
              </p>
              <p>
                Nossa equipe combina técnica impecável com sensibilidade artística para criar filmes que
                não apenas documentam, mas verdadeiramente celebram cada história única.
              </p>
            </div>
          </motion.section>

          <section className="about__values">
            <motion.div className="about__value" initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
              <h3>EXCELÊNCIA</h3>
              <p>Cada projeto recebe nossa total dedicação e atenção aos detalhes.</p>
            </motion.div>
            <motion.div className="about__value" initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
              <h3>ARTE</h3>
              <p>Abordagem cinematográfica que transforma momentos em obras de arte.</p>
            </motion.div>
            <motion.div className="about__value" initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
              <h3>CONEXÃO</h3>
              <p>Construímos relações autênticas para capturar a essência de cada casal.</p>
            </motion.div>
          </section>
        </>
      )}
    </div>
  );
}
