import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { projectsAPI } from '../api/api';
import './Projects.css';

export default function Projects() {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    projectsAPI.getAll({ per_page: 50 })
      .then(r => setProjects(r.data.data || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  return (
    <div className="projects-page">
      <section className="projects__hero">
        <div className="projects__hero-overlay" />
        <motion.div className="projects__hero-content" initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 1 }}>
          <h1 className="projects__hero-title">
            <span className="projects__hero-script">Runaway</span>Vows
          </h1>
          <p className="projects__hero-subtitle">PORTFÓLIO</p>
        </motion.div>
      </section>

      <section className="projects__list">
        {loading ? (
          <div className="projects__loading">Carregando projetos...</div>
        ) : projects.length === 0 ? (
          <div className="projects__empty">Nenhum projeto disponível ainda.</div>
        ) : (
          projects.map((project, i) => (
            <motion.div
              key={project.id}
              className={`projects__item ${i % 2 === 0 ? 'projects__item--left' : 'projects__item--right'}`}
              initial={{ opacity: 0, y: 40 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.6, delay: 0.1 }}
            >
              <div className="projects__item-media">
                {project.video_url ? (
                  <div className="projects__item-video">
                    <iframe
                      src={project.video_url}
                      title={project.title}
                      frameBorder="0"
                      allow="autoplay; fullscreen"
                      allowFullScreen
                    />
                  </div>
                ) : project.thumbnail_url ? (
                  <Link to={`/projects/${project.slug}`}>
                    <img src={project.thumbnail_url} alt={project.title} />
                  </Link>
                ) : (
                  <div className="projects__item-placeholder" />
                )}
              </div>

              <div className="projects__item-info">
                <h2 className="projects__item-title">
                  <Link to={`/projects/${project.slug}`}>
                    <span className="projects__item-names">{project.couple_names || project.title}</span>
                  </Link>
                </h2>
                <p className="projects__item-location">{project.location}</p>
                {project.description && (
                  <p className="projects__item-desc">{project.description}</p>
                )}
              </div>
            </motion.div>
          ))
        )}
      </section>

      {projects.length > 0 && (
        <section className="projects__featured">
          <p className="projects__featured-title">Assista aos filmes em destaque</p>
          <div className="projects__featured-grid">
            {projects.filter(p => p.is_featured).slice(0, 3).map(project => (
              <Link key={project.id} to={`/projects/${project.slug}`} className="projects__featured-item">
                {project.thumbnail_url && <img src={project.thumbnail_url} alt={project.title} />}
                <span>{project.couple_names || project.title} – {project.location}</span>
              </Link>
            ))}
          </div>
        </section>
      )}
    </div>
  );
}
