import React, { createContext, useContext, useState, useEffect } from 'react';
import { authAPI } from '../api/api';

const AuthContext = createContext();

const DEV_USER = {
  id: 1,
  username: 'admin',
  email: 'admin@stornoway.com',
  role: 'admin',
  name: 'Administrador'
};

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(localStorage.getItem('admin_token'));
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (token) {
      // Tentar recuperar user salvo no localStorage
      const savedUser = localStorage.getItem('admin_user');
      if (savedUser) {
        try {
          setUser(JSON.parse(savedUser));
          setLoading(false);
          return;
        } catch (e) { /* parse falhou, continuar */ }
      }
      if (token === 'dev-token') {
        setUser(DEV_USER);
        setLoading(false);
        return;
      }
      authAPI.getProfile()
        .then(res => {
          setUser(res.data.data);
          localStorage.setItem('admin_user', JSON.stringify(res.data.data));
        })
        .catch(() => {
          localStorage.removeItem('admin_token');
          localStorage.removeItem('admin_user');
          setToken(null);
        })
        .finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, [token]);

  const login = async (username, password) => {
    try {
      const res = await authAPI.login({ username, password });
      const { token: newToken, user: userData } = res.data.data;
      localStorage.setItem('admin_token', newToken);
      localStorage.setItem('admin_user', JSON.stringify(userData));
      setToken(newToken);
      setUser(userData);
      return userData;
    } catch (err) {
      // Modo dev: só aceita fallback se o backend não está acessível (erro de rede)
      const isNetworkError = !err.response;
      if (isNetworkError && username === 'admin' && password === 'admin123') {
        localStorage.setItem('admin_token', 'dev-token');
        localStorage.setItem('admin_user', JSON.stringify(DEV_USER));
        setToken('dev-token');
        setUser(DEV_USER);
        return DEV_USER;
      }
      throw err;
    }
  };

  const logout = () => {
    localStorage.removeItem('admin_token');
    localStorage.removeItem('admin_user');
    setToken(null);
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, token, loading, login, logout, isAuthenticated: !!user }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => useContext(AuthContext);
