import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { servicesAPI } from '../api/api';
import { useSite } from '../contexts/SiteContext';
import './Services.css';

const fadeIn = { hidden: { opacity: 0, y: 30 }, visible: { opacity: 1, y: 0, transition: { duration: 0.8 } } };

export default function Services() {
  const { getSetting } = useSite();
  const [services, setServices] = useState([]);

  useEffect(() => {
    servicesAPI.getAll().then(r => setServices(r.data.data || [])).catch(() => {});
  }, []);

  return (
    <div className="services-page">
      {/* Hero */}
      <section className="services__hero">
        <div className="services__hero-overlay" />
        <motion.div className="services__hero-content" initial="hidden" animate="visible" variants={fadeIn}>
          <p className="services__hero-label">EXPERIÊNCIA</p>
          <h1 className="services__hero-title">{getSetting('site_name', 'STORNOWAY')}</h1>
        </motion.div>
      </section>

      {/* Intro */}
      <motion.section className="services__intro" initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
        <div className="services__intro-grid">
          <div className="services__intro-image">
            <img src="https://images.unsplash.com/photo-1606216794074-735e91aa2c92?w=500" alt="" />
          </div>
          <div className="services__intro-text">
            <h2>FILMAGEM DE CASAMENTO</h2>
            <h3 className="services__intro-accent">FEITA SOB MEDIDA PARA VOCÊ</h3>
            <p>
              Nosso primeiro contato é o momento em que essa bela história tem início – e o investimento em que
              você deposita sua confiança. Cada detalhe é cuidado para criar um filme que
              capture a essência do seu casamento de uma forma única e inesquecível.
            </p>
            <Link to="/contact" className="services__btn">CONECTE-SE HOJE</Link>
          </div>
        </div>
      </motion.section>

      {/* Investimento */}
      <motion.section className="services__investment" initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
        <div className="services__investment-card">
          <p className="services__script">O Investimento</p>
          <h2>TODA GRANDE HISTÓRIA DE AMOR MERECE SER PRESERVADA COM INTENÇÃO E ARTE.</h2>
          <p className="services__investment-text">
            Com mais de cinco anos de experiência filmando casamentos ao redor do mundo, nossa equipe de destinos é
            dedicada a criar filmes que conectam e cada celebração, assim como seu amor.
          </p>
          <img src="https://images.unsplash.com/photo-1519741497674-611481863552?w=700" alt="Investimento" className="services__investment-img" />
          <p className="services__investment-price">NOSSOS PACOTES PARA 2026 COMEÇAM EM USD 20.000</p>
          <p className="services__investment-note">
            Quer sua celebração seja íntima ou um evento de mil pessoas do outro lado do mundo, o amor que
            sentimos através dos casamentos que filmamos e o processo criativo Cada proposta é feita sob
            medida para atender às necessidades específicas do seu evento.
          </p>
        </div>
      </motion.section>

      {/* Serviços */}
      {services.length > 0 && (
        <section className="services__list">
          <h2 className="services__list-title">SERVICES</h2>
          <div className="services__list-grid">
            {services.map((service, i) => (
              <motion.div
                key={service.id}
                className="services__card"
                initial={{ opacity: 0, y: 30 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ delay: i * 0.15 }}
              >
                {service.image_url && <img src={service.image_url} alt={service.title} />}
                <h3>{service.title}</h3>
                {service.short_description && <p>{service.short_description}</p>}
                {service.price_label && <span className="services__card-price">{service.price_label}</span>}
                {service.features && service.features.length > 0 && (
                  <ul>
                    {service.features.map((f, j) => <li key={j}>{f}</li>)}
                  </ul>
                )}
              </motion.div>
            ))}
          </div>
        </section>
      )}

      {/* FAQ */}
      <section className="services__faq">
        <h2>PERGUNTAS FREQUENTES</h2>
        <FAQ question="VOCÊS VIAJAM?" answer="Sim! Filmamos casamentos ao redor do mundo inteiro. Adoramos destinos únicos e estamos prontos para wherever o amor levar." />
        <FAQ question="ONDE VOCÊS ESTÃO LOCALIZADOS?" answer="Estamos baseados no Brasil, mas atendemos casais em qualquer lugar do mundo." />
        <FAQ question="VOCÊS OFERECEM DESCONTOS PARA DESTINOS ESPECÍFICOS?" answer="Cada proposta é personalizada. Entre em contato para discutirmos o seu evento." />
        <FAQ question="QUANDO MEUS FILMES SERÃO ENTREGUES?" answer="O prazo de entrega é de 8 a 12 semanas após o evento, garantindo a mais alta qualidade de edição." />
      </section>

      {/* CTA */}
      <section className="services__cta">
        <Link to="/contact" className="services__cta-btn">ENTRE EM CONTATO</Link>
      </section>
    </div>
  );
}

function FAQ({ question, answer }) {
  const [open, setOpen] = useState(false);
  return (
    <div className={`services__faq-item ${open ? 'services__faq-item--open' : ''}`} onClick={() => setOpen(!open)}>
      <div className="services__faq-question">
        <span>{question}</span>
        <span className="services__faq-toggle">{open ? '−' : '+'}</span>
      </div>
      {open && (
        <motion.div className="services__faq-answer" initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} transition={{ duration: 0.3 }}>
          <p>{answer}</p>
        </motion.div>
      )}
    </div>
  );
}
