import React, { useRef, useState } from 'react';
import ReactPlayer from 'react-player';
import { FiPlay, FiPause, FiVolume2, FiVolumeX } from 'react-icons/fi';

export default function VideoPlayer({ url, poster, autoplay = false, muted = true, loop = true, controls = false, className = '', overlay = false }) {
  const [playing, setPlaying] = useState(autoplay);
  const [isMuted, setIsMuted] = useState(muted);
  const [showControls, setShowControls] = useState(false);
  const playerRef = useRef(null);

  if (!url) return null;

  const style = {
    position: 'relative',
    width: '100%',
    height: '100%',
    overflow: 'hidden',
  };

  return (
    <div
      className={className}
      style={style}
      onMouseEnter={() => setShowControls(true)}
      onMouseLeave={() => setShowControls(false)}
    >
      <ReactPlayer
        ref={playerRef}
        url={url}
        playing={playing}
        muted={isMuted}
        loop={loop}
        width="100%"
        height="100%"
        controls={controls}
        light={poster || false}
        style={{ position: 'absolute', top: 0, left: 0 }}
        config={{
          youtube: { playerVars: { modestbranding: 1, rel: 0 } },
          vimeo: { playerOptions: { byline: false, portrait: false, title: false } }
        }}
      />

      {overlay && <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.3)', pointerEvents: 'none' }} />}

      {!controls && showControls && (
        <div style={{
          position: 'absolute', bottom: 20, right: 20, display: 'flex', gap: 12, zIndex: 5,
          opacity: 0.8, transition: 'opacity 0.3s'
        }}>
          <button
            onClick={() => setPlaying(!playing)}
            style={{ background: 'rgba(0,0,0,0.5)', border: 'none', color: '#fff', borderRadius: '50%', width: 40, height: 40, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
            aria-label={playing ? 'Pausar' : 'Reproduzir'}
          >
            {playing ? <FiPause size={16} /> : <FiPlay size={16} />}
          </button>
          <button
            onClick={() => setIsMuted(!isMuted)}
            style={{ background: 'rgba(0,0,0,0.5)', border: 'none', color: '#fff', borderRadius: '50%', width: 40, height: 40, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
            aria-label={isMuted ? 'Ativar som' : 'Silenciar'}
          >
            {isMuted ? <FiVolumeX size={16} /> : <FiVolume2 size={16} />}
          </button>
        </div>
      )}
    </div>
  );
}
