import React, { useState, useEffect, useCallback } from 'react';
import { toast } from 'react-toastify';
import { FiSave, FiUpload, FiTrash2 } from 'react-icons/fi';
import { ChromePicker } from 'react-color';
import { settingsAPI } from '../api/api';
import MediaPicker from './MediaPicker';

const FONT_OPTIONS = [
  'Cormorant Garamond', 'Great Vibes', 'Montserrat', 'Playfair Display', 'Lora',
  'Raleway', 'Open Sans', 'Roboto', 'Oswald', 'Dancing Script', 'Cinzel',
  'Josefin Sans', 'Merriweather', 'Prata', 'Bodoni Moda', 'Abril Fatface'
];

const SETTING_GROUPS = [
  {
    title: 'Identidade',
    settings: [
      { key: 'site_title', label: 'Nome do site', type: 'text' },
      { key: 'site_subtitle', label: 'Subtítulo', type: 'text' },
      { key: 'site_description', label: 'Descrição (SEO)', type: 'textarea' },
      { key: 'logo_url', label: 'Logo', type: 'image' },
      { key: 'favicon_url', label: 'Favicon', type: 'image' },
      { key: 'monogram', label: 'Monograma', type: 'text', placeholder: 'Ex: M&J' },
    ]
  },
  {
    title: 'Fontes',
    settings: [
      { key: 'font_heading', label: 'Fonte títulos', type: 'font' },
      { key: 'font_body', label: 'Fonte corpo', type: 'font' },
      { key: 'font_accent', label: 'Fonte decorativa', type: 'font' },
    ]
  },
  {
    title: 'Cores',
    settings: [
      { key: 'color_primary', label: 'Cor primária (dourado)', type: 'color' },
      { key: 'color_background', label: 'Cor de fundo', type: 'color' },
      { key: 'color_text', label: 'Cor do texto', type: 'color' },
      { key: 'color_accent', label: 'Cor destaque', type: 'color' },
    ]
  },
  {
    title: 'Redes Sociais',
    settings: [
      { key: 'social_instagram', label: 'Instagram URL', type: 'text' },
      { key: 'social_vimeo', label: 'Vimeo URL', type: 'text' },
      { key: 'social_youtube', label: 'YouTube URL', type: 'text' },
      { key: 'social_facebook', label: 'Facebook URL', type: 'text' },
      { key: 'social_tiktok', label: 'TikTok URL', type: 'text' },
    ]
  },
  {
    title: 'Animação Intro',
    settings: [
      { key: 'intro_enabled', label: 'Ativar intro', type: 'boolean' },
      { key: 'intro_logo_url', label: 'Logo da intro', type: 'image' },
      { key: 'intro_title', label: 'Título da intro', type: 'text' },
      { key: 'intro_subtitle', label: 'Subtítulo da intro', type: 'text' },
      { key: 'intro_duration', label: 'Duração (ms)', type: 'number' },
    ]
  },
  {
    title: 'Contato',
    settings: [
      { key: 'contact_email', label: 'E-mail', type: 'text' },
      { key: 'contact_phone', label: 'Telefone', type: 'text' },
      { key: 'contact_address', label: 'Endereço', type: 'textarea' },
    ]
  },
  {
    title: 'Rodapé',
    settings: [
      { key: 'footer_text', label: 'Texto do rodapé', type: 'textarea' },
      { key: 'copyright_text', label: 'Copyright', type: 'text' },
    ]
  }
];

function ColorInput({ value, onChange }) {
  const [show, setShow] = useState(false);
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 8, position: 'relative' }}>
      <div
        style={{ width: 36, height: 36, borderRadius: 6, border: '2px solid #2a2a3e', cursor: 'pointer', background: value || '#000' }}
        onClick={() => setShow(!show)}
      />
      <input value={value || ''} onChange={e => onChange(e.target.value)} className="admin-input" style={{ flex: 1 }} />
      {show && (
        <div style={{ position: 'absolute', zIndex: 100, top: 44, left: 0 }}>
          <div style={{ position: 'fixed', inset: 0 }} onClick={() => setShow(false)} />
          <ChromePicker color={value || '#000'} onChange={c => onChange(c.hex)} disableAlpha />
        </div>
      )}
    </div>
  );
}

function FontInput({ value, onChange }) {
  return (
    <div>
      <select value={value || ''} onChange={e => onChange(e.target.value)} className="admin-input">
        <option value="">Selecione...</option>
        {FONT_OPTIONS.map(f => <option key={f} value={f}>{f}</option>)}
      </select>
      {value && (
        <p style={{ fontFamily: `"${value}", serif`, fontSize: 18, color: '#ccc', marginTop: 8, padding: 8, background: '#12121e', borderRadius: 4 }}>
          Exemplo de texto com "{value}"
        </p>
      )}
    </div>
  );
}

export default function SettingsEditor() {
  const [settings, setSettings] = useState({});
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [showPicker, setShowPicker] = useState(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await settingsAPI.getAll();
      const map = {};
      (res.data.data || []).forEach(s => { map[s.setting_key] = s.setting_value; });
      setSettings(map);
    } catch { toast.error('Erro ao carregar configurações'); }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { load(); }, [load]);

  const updateSetting = (key, value) => {
    setSettings(prev => ({ ...prev, [key]: value }));
  };

  const saveAll = async () => {
    setSaving(true);
    try {
      const items = Object.entries(settings).map(([key, val]) => ({ setting_key: key, setting_value: val }));
      await settingsAPI.bulkUpdate({ settings: items });
      toast.success('Configurações salvas!');
    } catch { toast.error('Erro ao salvar'); }
    finally { setSaving(false); }
  };

  if (loading) return <div className="admin-card" style={{ textAlign: 'center', padding: 40, color: '#888' }}>Carregando...</div>;

  return (
    <div>
      <div className="admin-page-header">
        <h1>Configurações do Site</h1>
        <button onClick={saveAll} disabled={saving} className="admin-btn admin-btn--primary">
          <FiSave size={14} /> {saving ? 'Salvando...' : 'Salvar Tudo'}
        </button>
      </div>

      {SETTING_GROUPS.map(group => (
        <div key={group.title} className="admin-card" style={{ marginBottom: 16 }}>
          <h3 style={{ color: '#c9a96e', marginTop: 0, marginBottom: 16, fontSize: 14, textTransform: 'uppercase', letterSpacing: '0.5px' }}>{group.title}</h3>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
            {group.settings.map(s => (
              <div key={s.key}>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>{s.label}</label>
                {s.type === 'text' && (
                  <input value={settings[s.key] || ''} onChange={e => updateSetting(s.key, e.target.value)} className="admin-input" placeholder={s.placeholder} />
                )}
                {s.type === 'number' && (
                  <input type="number" value={settings[s.key] || ''} onChange={e => updateSetting(s.key, e.target.value)} className="admin-input" />
                )}
                {s.type === 'textarea' && (
                  <textarea value={settings[s.key] || ''} onChange={e => updateSetting(s.key, e.target.value)} className="admin-input" rows={3} />
                )}
                {s.type === 'boolean' && (
                  <label style={{ display: 'flex', alignItems: 'center', gap: 6, color: '#ccc', fontSize: 13, cursor: 'pointer' }}>
                    <input type="checkbox" checked={settings[s.key] === '1' || settings[s.key] === true} onChange={e => updateSetting(s.key, e.target.checked ? '1' : '0')} style={{ accentColor: '#c9a96e' }} />
                    {settings[s.key] === '1' ? 'Ativado' : 'Desativado'}
                  </label>
                )}
                {s.type === 'color' && (
                  <ColorInput value={settings[s.key]} onChange={v => updateSetting(s.key, v)} />
                )}
                {s.type === 'font' && (
                  <FontInput value={settings[s.key]} onChange={v => updateSetting(s.key, v)} />
                )}
                {s.type === 'image' && (
                  <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                    {settings[s.key] && <img src={settings[s.key]} alt="" style={{ width: 50, height: 50, objectFit: 'contain', borderRadius: 4, background: '#1a1a2e' }} />}
                    <button onClick={() => setShowPicker(s.key)} className="admin-btn admin-btn--secondary admin-btn--small"><FiUpload size={12} /> Selecionar</button>
                    {settings[s.key] && <button onClick={() => updateSetting(s.key, '')} className="admin-btn admin-btn--danger admin-btn--small"><FiTrash2 size={12} /></button>}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      ))}

      {showPicker && (
        <MediaPicker
          type="image"
          onSelect={(url) => { updateSetting(showPicker, url); setShowPicker(null); }}
          onClose={() => setShowPicker(null)}
        />
      )}
    </div>
  );
}
