import React from 'react';
import { Link } from 'react-router-dom';
import { FiInstagram, FiYoutube, FiMail } from 'react-icons/fi';
import { useSite } from '../contexts/SiteContext';
import './Footer.css';

export default function Footer() {
  const { getSetting, menuItems } = useSite();

  return (
    <footer className="footer">
      <div className="footer__inner">
        <div className="footer__brand">
          <h3 className="footer__title">{getSetting('site_name', 'STORNOWAY')}</h3>
          <p className="footer__tagline">{getSetting('site_tagline', 'FILM HOUSE')}</p>
        </div>

        <nav className="footer__nav">
          {menuItems.map(item => (
            <Link key={item.id} to={item.url} className="footer__link">
              {item.title}
            </Link>
          ))}
        </nav>

        <div className="footer__social">
          {getSetting('instagram_url') && (
            <a href={getSetting('instagram_url')} target="_blank" rel="noopener noreferrer" aria-label="Instagram">
              <FiInstagram size={18} />
            </a>
          )}
          {getSetting('youtube_url') && (
            <a href={getSetting('youtube_url')} target="_blank" rel="noopener noreferrer" aria-label="YouTube">
              <FiYoutube size={18} />
            </a>
          )}
          {getSetting('contact_email') && (
            <a href={`mailto:${getSetting('contact_email')}`} aria-label="Email">
              <FiMail size={18} />
            </a>
          )}
        </div>

        <div className="footer__bottom">
          <p>{getSetting('footer_text', `© ${new Date().getFullYear()} Stornoway Films`)}</p>
        </div>
      </div>
    </footer>
  );
}
