import React, { useState, useEffect, useCallback } from 'react';
import { toast } from 'react-toastify';
import { FiPlus, FiTrash2, FiEdit3, FiX, FiCheck, FiEye, FiEyeOff, FiStar, FiFilm } from 'react-icons/fi';
import { projectsAPI } from '../api/api';
import MediaPicker from './MediaPicker';

export default function ProjectsManager() {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [editing, setEditing] = useState(null);
  const [showMediaPicker, setShowMediaPicker] = useState(null);
  const [form, setForm] = useState({
    title: '', subtitle: '', description: '', video_url: '', thumbnail_url: '',
    location: '', date: '', couple_names: '', is_featured: 0, is_published: 1, gallery: []
  });

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await projectsAPI.getAll();
      setProjects(res.data.data || []);
    } catch { toast.error('Erro ao carregar projetos'); }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { load(); }, [load]);

  const openForm = (project = null) => {
    if (project) {
      setEditing(project.id);
      setForm({
        title: project.title || '', subtitle: project.subtitle || '', description: project.description || '',
        video_url: project.video_url || '', thumbnail_url: project.thumbnail_url || '',
        location: project.location || '', date: project.date || '', couple_names: project.couple_names || '',
        is_featured: project.is_featured || 0, is_published: project.is_published ?? 1,
        gallery: project.gallery ? (typeof project.gallery === 'string' ? JSON.parse(project.gallery) : project.gallery) : []
      });
    } else {
      setEditing(null);
      setForm({ title: '', subtitle: '', description: '', video_url: '', thumbnail_url: '', location: '', date: '', couple_names: '', is_featured: 0, is_published: 1, gallery: [] });
    }
    setShowForm(true);
  };

  const save = async () => {
    if (!form.title.trim()) { toast.warning('Título obrigatório'); return; }
    try {
      const data = { ...form, gallery: JSON.stringify(form.gallery) };
      if (editing) { await projectsAPI.update(editing, data); toast.success('Projeto atualizado!'); }
      else { await projectsAPI.create(data); toast.success('Projeto criado!'); }
      setShowForm(false);
      load();
    } catch { toast.error('Erro ao salvar'); }
  };

  const remove = async (id) => {
    if (!window.confirm('Excluir este projeto?')) return;
    try { await projectsAPI.delete(id); toast.success('Excluído!'); load(); }
    catch { toast.error('Erro ao excluir'); }
  };

  const addGalleryItem = (url) => {
    setForm(f => ({ ...f, gallery: [...f.gallery, { url, caption: '' }] }));
    setShowMediaPicker(null);
  };

  const removeGalleryItem = (idx) => {
    setForm(f => ({ ...f, gallery: f.gallery.filter((_, i) => i !== idx) }));
  };

  return (
    <div>
      <div className="admin-page-header">
        <h1>Projetos</h1>
        <button onClick={() => openForm()} className="admin-btn admin-btn--primary"><FiPlus size={16} /> Novo Projeto</button>
      </div>

      {loading ? <div className="admin-card" style={{ textAlign: 'center', padding: 40, color: '#888' }}>Carregando...</div> : (
        <div className="admin-card">
          <table className="admin-table">
            <thead><tr><th>Thumb</th><th>Título</th><th>Casal</th><th>Local</th><th>Destaque</th><th>Status</th><th>Ações</th></tr></thead>
            <tbody>
              {projects.map(p => (
                <tr key={p.id}>
                  <td>
                    <div style={{ width: 60, height: 40, borderRadius: 4, overflow: 'hidden', background: '#1a1a2e', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                      {p.thumbnail_url ? <img src={p.thumbnail_url} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <FiFilm size={16} color="#666" />}
                    </div>
                  </td>
                  <td><strong>{p.title}</strong></td>
                  <td style={{ color: '#aaa' }}>{p.couple_names || '-'}</td>
                  <td style={{ color: '#aaa' }}>{p.location || '-'}</td>
                  <td>{p.is_featured ? <FiStar size={14} color="#c9a96e" /> : '-'}</td>
                  <td><span className={`admin-badge ${p.is_published ? 'admin-badge--success' : 'admin-badge--warning'}`}>{p.is_published ? 'Publicado' : 'Rascunho'}</span></td>
                  <td>
                    <div style={{ display: 'flex', gap: 4 }}>
                      <button onClick={() => openForm(p)} className="admin-btn admin-btn--secondary admin-btn--small"><FiEdit3 size={12} /></button>
                      <button onClick={() => remove(p.id)} className="admin-btn admin-btn--danger admin-btn--small"><FiTrash2 size={12} /></button>
                    </div>
                  </td>
                </tr>
              ))}
              {projects.length === 0 && <tr><td colSpan={7} style={{ textAlign: 'center', color: '#888', padding: 30 }}>Nenhum projeto ainda.</td></tr>}
            </tbody>
          </table>
        </div>
      )}

      {/* Form Modal */}
      {showForm && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.7)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }}
          onClick={e => e.target === e.currentTarget && setShowForm(false)}>
          <div className="admin-card" style={{ width: 600, maxHeight: '85vh', overflowY: 'auto' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
              <h3 style={{ color: '#fff', margin: 0 }}>{editing ? 'Editar Projeto' : 'Novo Projeto'}</h3>
              <button onClick={() => setShowForm(false)} style={{ background: 'none', border: 'none', color: '#888', cursor: 'pointer' }}><FiX size={18} /></button>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
                <div>
                  <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Título *</label>
                  <input value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} className="admin-input" />
                </div>
                <div>
                  <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Subtítulo</label>
                  <input value={form.subtitle} onChange={e => setForm(f => ({ ...f, subtitle: e.target.value }))} className="admin-input" />
                </div>
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
                <div>
                  <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Nomes do casal</label>
                  <input value={form.couple_names} onChange={e => setForm(f => ({ ...f, couple_names: e.target.value }))} className="admin-input" placeholder="Maria & João" />
                </div>
                <div>
                  <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Local</label>
                  <input value={form.location} onChange={e => setForm(f => ({ ...f, location: e.target.value }))} className="admin-input" />
                </div>
              </div>
              <div>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Data</label>
                <input type="date" value={form.date} onChange={e => setForm(f => ({ ...f, date: e.target.value }))} className="admin-input" style={{ width: 'auto' }} />
              </div>
              <div>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Descrição</label>
                <textarea value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} className="admin-input" rows={4} />
              </div>
              <div>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>URL do Vídeo (Vimeo/YouTube)</label>
                <input value={form.video_url} onChange={e => setForm(f => ({ ...f, video_url: e.target.value }))} className="admin-input" placeholder="https://vimeo.com/..." />
              </div>
              <div>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Thumbnail</label>
                <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                  {form.thumbnail_url && <img src={form.thumbnail_url} alt="" style={{ width: 80, height: 50, objectFit: 'cover', borderRadius: 4 }} />}
                  <button onClick={() => setShowMediaPicker('thumbnail')} className="admin-btn admin-btn--secondary admin-btn--small">Selecionar Imagem</button>
                  {form.thumbnail_url && <button onClick={() => setForm(f => ({ ...f, thumbnail_url: '' }))} className="admin-btn admin-btn--danger admin-btn--small"><FiTrash2 size={12} /></button>}
                </div>
              </div>

              {/* Gallery */}
              <div>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Galeria</label>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(80px, 1fr))', gap: 6 }}>
                  {form.gallery.map((item, idx) => (
                    <div key={idx} style={{ position: 'relative', aspectRatio: '1', borderRadius: 4, overflow: 'hidden', border: '1px solid #2a2a3e' }}>
                      <img src={item.url} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                      <button onClick={() => removeGalleryItem(idx)} style={{ position: 'absolute', top: 2, right: 2, background: 'rgba(0,0,0,0.7)', border: 'none', color: '#e74c3c', padding: 2, borderRadius: 4, cursor: 'pointer', display: 'flex' }}><FiX size={10} /></button>
                    </div>
                  ))}
                  <button onClick={() => setShowMediaPicker('gallery')} style={{ aspectRatio: '1', background: '#12121e', border: '2px dashed #2a2a3e', borderRadius: 4, display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', color: '#888' }}><FiPlus size={16} /></button>
                </div>
              </div>

              <div style={{ display: 'flex', gap: 16 }}>
                <label style={{ display: 'flex', alignItems: 'center', gap: 6, color: '#ccc', fontSize: 13, cursor: 'pointer' }}>
                  <input type="checkbox" checked={!!form.is_featured} onChange={e => setForm(f => ({ ...f, is_featured: e.target.checked ? 1 : 0 }))} style={{ accentColor: '#c9a96e' }} /> Em destaque
                </label>
                <label style={{ display: 'flex', alignItems: 'center', gap: 6, color: '#ccc', fontSize: 13, cursor: 'pointer' }}>
                  <input type="checkbox" checked={!!form.is_published} onChange={e => setForm(f => ({ ...f, is_published: e.target.checked ? 1 : 0 }))} style={{ accentColor: '#c9a96e' }} /> Publicado
                </label>
              </div>
            </div>

            <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 20 }}>
              <button onClick={() => setShowForm(false)} className="admin-btn admin-btn--secondary">Cancelar</button>
              <button onClick={save} className="admin-btn admin-btn--primary"><FiCheck size={14} /> {editing ? 'Salvar' : 'Criar'}</button>
            </div>
          </div>
        </div>
      )}

      {showMediaPicker && (
        <MediaPicker
          type="image"
          onSelect={(url) => {
            if (showMediaPicker === 'thumbnail') setForm(f => ({ ...f, thumbnail_url: url }));
            else addGalleryItem(url);
          }}
          onClose={() => setShowMediaPicker(null)}
        />
      )}
    </div>
  );
}
