import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

import { AuthProvider } from './contexts/AuthContext';
import { SiteProvider } from './contexts/SiteContext';
import IntroAnimation from './components/IntroAnimation';
import Navbar from './components/Navbar';
import Footer from './components/Footer';

// Páginas públicas
import Home from './pages/Home';
import About from './pages/About';
import Projects from './pages/Projects';
import ProjectDetail from './pages/ProjectDetail';
import Services from './pages/Services';
import Contact from './pages/Contact';
import DynamicPage from './pages/DynamicPage';

// Admin
import AdminLogin from './admin/AdminLogin';
import AdminLayout from './admin/AdminLayout';
import Dashboard from './admin/Dashboard';
import PageBuilder from './admin/PageBuilder';
import MediaManager from './admin/MediaManager';
import MenuEditor from './admin/MenuEditor';
import ProjectsManager from './admin/ProjectsManager';
import ServicesManager from './admin/ServicesManager';
import SettingsEditor from './admin/SettingsEditor';
import ContactSubmissions from './admin/ContactSubmissions';
import TestimonialsManager from './admin/TestimonialsManager';

function PublicLayout({ children }) {
  const [showIntro, setShowIntro] = useState(true);
  const [introComplete, setIntroComplete] = useState(false);

  useEffect(() => {
    const hasSeenIntro = sessionStorage.getItem('intro_seen');
    if (hasSeenIntro) {
      setShowIntro(false);
      setIntroComplete(true);
    }
  }, []);

  const handleIntroComplete = () => {
    setIntroComplete(true);
    sessionStorage.setItem('intro_seen', 'true');
    setTimeout(() => setShowIntro(false), 500);
  };

  return (
    <>
      {showIntro && !introComplete && (
        <IntroAnimation onComplete={handleIntroComplete} />
      )}
      <div style={{ opacity: introComplete ? 1 : 0, transition: 'opacity 0.8s ease' }}>
        <Navbar />
        <main>{children}</main>
        <Footer />
      </div>
    </>
  );
}

function App() {
  return (
    <Router>
      <AuthProvider>
        <SiteProvider>
          <ToastContainer position="top-right" autoClose={3000} theme="dark" />
          <Routes>
            {/* Rotas Admin */}
            <Route path="/admin/login" element={<AdminLogin />} />
            <Route path="/admin" element={<AdminLayout />}>
              <Route index element={<Dashboard />} />
              <Route path="pages" element={<PageBuilder />} />
              <Route path="pages/:id" element={<PageBuilder />} />
              <Route path="media" element={<MediaManager />} />
              <Route path="menu" element={<MenuEditor />} />
              <Route path="projects" element={<ProjectsManager />} />
              <Route path="services" element={<ServicesManager />} />
              <Route path="settings" element={<SettingsEditor />} />
              <Route path="contacts" element={<ContactSubmissions />} />
              <Route path="testimonials" element={<TestimonialsManager />} />
            </Route>

            {/* Rotas Públicas */}
            <Route path="/" element={<PublicLayout><Home /></PublicLayout>} />
            <Route path="/about" element={<PublicLayout><About /></PublicLayout>} />
            <Route path="/projects" element={<PublicLayout><Projects /></PublicLayout>} />
            <Route path="/projects/:slug" element={<PublicLayout><ProjectDetail /></PublicLayout>} />
            <Route path="/services" element={<PublicLayout><Services /></PublicLayout>} />
            <Route path="/contact" element={<PublicLayout><Contact /></PublicLayout>} />
            <Route path="/page/:slug" element={<PublicLayout><DynamicPage /></PublicLayout>} />
          </Routes>
        </SiteProvider>
      </AuthProvider>
    </Router>
  );
}

export default App;
