import React from 'react';
import { motion } from 'framer-motion';
import VideoPlayer from './VideoPlayer';

const fadeIn = {
  hidden: { opacity: 0, y: 30 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.8 } }
};

export default function SectionRenderer({ section }) {
  const { section_type, content = {}, styles = {} } = section;

  const sectionStyle = {
    padding: styles.padding || '60px 20px',
    background: styles.background || '#ffffff',
    color: styles.text_color || '#333333',
    textAlign: styles.text_align || 'center',
    position: 'relative',
    overflow: 'hidden',
  };

  switch (section_type) {
    case 'hero':
      return (
        <section style={{ ...sectionStyle, height: styles.height || '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 0 }}>
          {content.video_url ? (
            <VideoPlayer url={content.video_url} autoplay muted loop overlay className="hero-video" />
          ) : content.image_url ? (
            <div style={{ position: 'absolute', inset: 0, backgroundImage: `url(${content.image_url})`, backgroundSize: 'cover', backgroundPosition: 'center' }}>
              <div style={{ position: 'absolute', inset: 0, background: `rgba(0,0,0,${styles.overlay_opacity || 0.3})` }} />
            </div>
          ) : null}
          <motion.div style={{ position: 'relative', zIndex: 2, textAlign: 'center', color: '#fff', padding: '0 20px' }} initial="hidden" animate="visible" variants={fadeIn}>
            {content.subtitle && <p style={{ fontFamily: "'Montserrat', sans-serif", fontSize: '0.75rem', letterSpacing: '0.3em', marginBottom: 20, opacity: 0.8 }}>{content.subtitle}</p>}
            <h1 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 'clamp(2.5rem, 6vw, 5rem)', fontWeight: 300, letterSpacing: '0.15em', margin: '0 0 16px', lineHeight: 1.1 }}>{content.title}</h1>
            {content.description && <p style={{ fontFamily: "'Montserrat', sans-serif", fontSize: '0.8rem', letterSpacing: '0.2em', opacity: 0.7, maxWidth: 600, margin: '0 auto' }}>{content.description}</p>}
            {content.button_text && (
              <a href={content.button_url || '#'} style={{ display: 'inline-block', marginTop: 32, padding: '14px 40px', border: '1px solid rgba(255,255,255,0.5)', color: '#fff', textDecoration: 'none', fontFamily: "'Montserrat', sans-serif", fontSize: '0.7rem', letterSpacing: '0.2em', transition: 'all 0.3s' }}>
                {content.button_text}
              </a>
            )}
          </motion.div>
        </section>
      );

    case 'text':
      return (
        <motion.section style={sectionStyle} initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
          <div style={{ maxWidth: styles.max_width || '800px', margin: '0 auto' }}>
            {content.title && <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 'clamp(1.5rem, 3vw, 2.5rem)', fontWeight: 400, letterSpacing: '0.1em', marginBottom: 24 }}>{content.title}</h2>}
            {content.content && <div dangerouslySetInnerHTML={{ __html: content.content }} style={{ fontFamily: "'Montserrat', sans-serif", fontSize: '0.85rem', lineHeight: 1.8, opacity: 0.8 }} />}
          </div>
        </motion.section>
      );

    case 'image':
      return (
        <motion.section style={sectionStyle} initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
          {content.image_url && (
            <div style={{ maxWidth: styles.max_width || '100%', margin: '0 auto' }}>
              {content.link_url ? (
                <a href={content.link_url}><img src={content.image_url} alt={content.alt_text || ''} style={{ width: content.width || '100%', height: content.height || 'auto', objectFit: 'cover' }} /></a>
              ) : (
                <img src={content.image_url} alt={content.alt_text || ''} style={{ width: content.width || '100%', height: content.height || 'auto', objectFit: 'cover' }} />
              )}
              {content.caption && <p style={{ fontFamily: "'Montserrat', sans-serif", fontSize: '0.75rem', marginTop: 12, opacity: 0.6 }}>{content.caption}</p>}
            </div>
          )}
        </motion.section>
      );

    case 'video':
      return (
        <section style={{ ...sectionStyle, padding: content.fullwidth ? 0 : sectionStyle.padding }}>
          <div style={{ maxWidth: content.fullwidth ? '100%' : '900px', margin: '0 auto', aspectRatio: '16/9' }}>
            {content.title && <h3 style={{ fontFamily: "'Cormorant Garamond', serif", marginBottom: 20 }}>{content.title}</h3>}
            <VideoPlayer url={content.video_url} poster={content.poster_url} autoplay={content.autoplay} muted={content.muted} loop={content.loop} controls />
          </div>
        </section>
      );

    case 'gallery':
      return (
        <motion.section style={sectionStyle} initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
          {content.title && <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: '2rem', marginBottom: 40 }}>{content.title}</h2>}
          <div style={{ display: 'grid', gridTemplateColumns: `repeat(${content.columns || 3}, 1fr)`, gap: content.gap || 16, maxWidth: 1200, margin: '0 auto' }}>
            {(content.items || []).map((item, i) => (
              <motion.div key={i} initial={{ opacity: 0 }} whileInView={{ opacity: 1 }} transition={{ delay: i * 0.1 }} style={{ overflow: 'hidden', aspectRatio: '4/3' }}>
                {item.type === 'video' ? (
                  <VideoPlayer url={item.url} poster={item.thumbnail} controls />
                ) : (
                  <img src={item.url} alt={item.alt || ''} style={{ width: '100%', height: '100%', objectFit: 'cover', transition: 'transform 0.5s' }} />
                )}
              </motion.div>
            ))}
          </div>
        </motion.section>
      );

    case 'cta':
      return (
        <section style={{ ...sectionStyle, backgroundImage: content.background_image ? `url(${content.background_image})` : 'none', backgroundSize: 'cover', backgroundPosition: 'center' }}>
          {content.background_image && <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.4)' }} />}
          <motion.div style={{ position: 'relative', zIndex: 2, maxWidth: 700, margin: '0 auto' }} initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
            {content.title && <p style={{ fontFamily: "'Great Vibes', cursive", fontSize: '1.8rem', marginBottom: 8 }}>{content.title}</p>}
            {content.subtitle && <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 'clamp(1.5rem, 3vw, 2.2rem)', fontWeight: 400, letterSpacing: '0.05em', textTransform: 'uppercase', marginBottom: 32 }}>{content.subtitle}</h2>}
            {content.button_text && (
              <a href={content.button_url || '/contact'} style={{ display: 'inline-block', padding: '14px 48px', background: styles.button_bg || '#1a1a2e', color: styles.button_color || '#fff', textDecoration: 'none', fontFamily: "'Montserrat', sans-serif", fontSize: '0.7rem', letterSpacing: '0.2em' }}>
                {content.button_text}
              </a>
            )}
          </motion.div>
        </section>
      );

    case 'testimonial':
      return (
        <section style={{ ...sectionStyle, backgroundImage: content.background_image ? `url(${content.background_image})` : 'none', backgroundSize: 'cover', backgroundPosition: 'center', backgroundAttachment: 'fixed' }}>
          {content.background_image && <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.5)' }} />}
          <div style={{ position: 'relative', zIndex: 2, maxWidth: 700, margin: '0 auto' }}>
            {(content.items || []).map((item, i) => (
              <motion.div key={i} initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn} style={{ marginBottom: 40 }}>
                <p style={{ fontFamily: "'Great Vibes', cursive", fontSize: '1.5rem', marginBottom: 16, color: '#d4af37' }}>{item.name}</p>
                <blockquote style={{ fontFamily: "'Montserrat', sans-serif", fontSize: '0.8rem', lineHeight: 1.8, fontStyle: 'italic', opacity: 0.9, margin: '0 0 24px' }}>"{item.text}"</blockquote>
                {item.video_url && <a href={item.video_url} style={{ display: 'inline-block', padding: '10px 30px', border: '1px solid currentColor', textDecoration: 'none', color: 'inherit', fontFamily: "'Montserrat', sans-serif", fontSize: '0.65rem', letterSpacing: '0.2em' }}>ASSISTA AO FILME</a>}
              </motion.div>
            ))}
          </div>
        </section>
      );

    case 'founders':
      return (
        <section style={{ ...sectionStyle, background: styles.background || '#1a1a2e', color: '#fff' }}>
          <div style={{ maxWidth: 1100, margin: '0 auto', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 60, alignItems: 'center' }}>
            {content.image_url && <img src={content.image_url} alt={content.names || ''} style={{ width: '100%', objectFit: 'cover' }} />}
            <div style={{ textAlign: 'left' }}>
              <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 'clamp(2rem, 4vw, 3.5rem)', fontWeight: 300, marginBottom: 24, lineHeight: 1.1 }}>{content.title}</h2>
              <div style={{ width: 60, height: 1, background: '#d4af37', marginBottom: 24 }} />
              <h3 style={{ fontFamily: "'Montserrat', sans-serif", fontSize: '0.8rem', letterSpacing: '0.15em', marginBottom: 20 }}>{content.names}</h3>
              <p style={{ fontFamily: "'Montserrat', sans-serif", fontSize: '0.85rem', lineHeight: 1.8, opacity: 0.8 }}>{content.description}</p>
              {content.button_text && <a href={content.button_url || '/about'} style={{ display: 'inline-block', marginTop: 24, padding: '12px 40px', background: 'rgba(255,255,255,0.1)', color: '#fff', textDecoration: 'none', fontFamily: "'Montserrat', sans-serif", fontSize: '0.7rem', letterSpacing: '0.15em' }}>{content.button_text}</a>}
            </div>
          </div>
        </section>
      );

    case 'custom':
      return (
        <section style={sectionStyle}>
          {content.css && <style>{content.css}</style>}
          <div dangerouslySetInnerHTML={{ __html: content.html || '' }} />
        </section>
      );

    default:
      return null;
  }
}
