import React, { useState, useEffect, useCallback } from 'react';
import { DndContext, closestCenter, PointerSensor, useSensor, useSensors } from '@dnd-kit/core';
import { SortableContext, verticalListSortingStrategy, useSortable, arrayMove } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { toast } from 'react-toastify';
import { FiPlus, FiTrash2, FiMove, FiEdit3, FiX, FiCheck, FiExternalLink } from 'react-icons/fi';
import { menuAPI, pagesAPI } from '../api/api';

function SortableMenuItem({ item, onEdit, onDelete }) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({ id: item.id });
  const style = { transform: CSS.Transform.toString(transform), transition, opacity: isDragging ? 0.5 : 1 };

  return (
    <div ref={setNodeRef} style={style} className="admin-card" {...{ style: { ...style, display: 'flex', alignItems: 'center', gap: 10, padding: '10px 14px', marginBottom: 6 } }}>
      <button {...attributes} {...listeners} style={{ cursor: 'grab', background: 'none', border: 'none', color: '#666', padding: 4, display: 'flex' }}>
        <FiMove size={16} />
      </button>
      <div style={{ flex: 1 }}>
        <strong style={{ color: '#fff', fontSize: 14 }}>{item.title}</strong>
        <span style={{ color: '#888', fontSize: 12, marginLeft: 8 }}>
          {item.link_type === 'page' ? `Página: /${item.page_slug || ''}` : item.url}
        </span>
      </div>
      <span className={`admin-badge ${item.is_active ? 'admin-badge--success' : 'admin-badge--warning'}`}>
        {item.is_active ? 'Ativo' : 'Oculto'}
      </span>
      <button onClick={() => onEdit(item)} className="admin-btn admin-btn--secondary admin-btn--small"><FiEdit3 size={12} /></button>
      <button onClick={() => onDelete(item.id)} className="admin-btn admin-btn--danger admin-btn--small"><FiTrash2 size={12} /></button>
    </div>
  );
}

export default function MenuEditor() {
  const [items, setItems] = useState([]);
  const [pages, setPages] = useState([]);
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState({ title: '', link_type: 'page', page_id: '', url: '', is_active: 1, open_new_tab: 0 });
  const [showForm, setShowForm] = useState(false);

  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 5 } }));

  const load = useCallback(async () => {
    try {
      const [menuRes, pagesRes] = await Promise.all([menuAPI.getAll(), pagesAPI.getAll()]);
      setItems(menuRes.data.data || []);
      setPages(pagesRes.data.data || []);
    } catch { toast.error('Erro ao carregar menu'); }
  }, []);

  useEffect(() => { load(); }, [load]);

  const openForm = (item = null) => {
    if (item) {
      setEditing(item.id);
      setForm({ title: item.title, link_type: item.link_type || 'page', page_id: item.page_id || '', url: item.url || '', is_active: item.is_active, open_new_tab: item.open_new_tab || 0 });
    } else {
      setEditing(null);
      setForm({ title: '', link_type: 'page', page_id: '', url: '', is_active: 1, open_new_tab: 0 });
    }
    setShowForm(true);
  };

  const save = async () => {
    if (!form.title.trim()) { toast.warning('Título obrigatório'); return; }
    try {
      if (editing) {
        await menuAPI.update(editing, form);
        toast.success('Item atualizado!');
      } else {
        await menuAPI.create(form);
        toast.success('Item criado!');
      }
      setShowForm(false);
      load();
    } catch { toast.error('Erro ao salvar'); }
  };

  const remove = async (id) => {
    if (!window.confirm('Excluir este item do menu?')) return;
    try {
      await menuAPI.delete(id);
      toast.success('Item excluído!');
      load();
    } catch { toast.error('Erro ao excluir'); }
  };

  const handleDragEnd = async (event) => {
    const { active, over } = event;
    if (!over || active.id === over.id) return;
    const oldIndex = items.findIndex(i => i.id === active.id);
    const newIndex = items.findIndex(i => i.id === over.id);
    const reordered = arrayMove(items, oldIndex, newIndex);
    setItems(reordered);
    try {
      await menuAPI.reorder({ order: reordered.map(i => i.id) });
    } catch { toast.error('Erro ao reordenar'); }
  };

  return (
    <div>
      <div className="admin-page-header">
        <h1>Menu do Site</h1>
        <button onClick={() => openForm()} className="admin-btn admin-btn--primary"><FiPlus size={16} /> Novo Item</button>
      </div>

      <p style={{ color: '#888', marginBottom: 16, fontSize: 13 }}>Arraste os itens para reordenar. O menu será atualizado automaticamente no site.</p>

      <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
        <SortableContext items={items.map(i => i.id)} strategy={verticalListSortingStrategy}>
          {items.map(item => (
            <SortableMenuItem key={item.id} item={item} onEdit={openForm} onDelete={remove} />
          ))}
        </SortableContext>
      </DndContext>

      {items.length === 0 && (
        <div className="admin-card" style={{ textAlign: 'center', padding: 40, color: '#888' }}>Nenhum item no menu ainda.</div>
      )}

      {/* Form Modal */}
      {showForm && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.7)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }}
          onClick={e => e.target === e.currentTarget && setShowForm(false)}>
          <div className="admin-card" style={{ width: 440, maxHeight: '80vh', overflowY: 'auto' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
              <h3 style={{ color: '#fff', margin: 0 }}>{editing ? 'Editar Item' : 'Novo Item'}</h3>
              <button onClick={() => setShowForm(false)} style={{ background: 'none', border: 'none', color: '#888', cursor: 'pointer' }}><FiX size={18} /></button>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              <div>
                <label style={{ fontSize: 12, color: '#aaa', marginBottom: 4, display: 'block' }}>Título</label>
                <input value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} className="admin-input" autoFocus />
              </div>
              <div>
                <label style={{ fontSize: 12, color: '#aaa', marginBottom: 4, display: 'block' }}>Tipo de link</label>
                <select value={form.link_type} onChange={e => setForm(f => ({ ...f, link_type: e.target.value }))} className="admin-input">
                  <option value="page">Página do site</option>
                  <option value="external">Link externo</option>
                </select>
              </div>
              {form.link_type === 'page' ? (
                <div>
                  <label style={{ fontSize: 12, color: '#aaa', marginBottom: 4, display: 'block' }}>Página</label>
                  <select value={form.page_id} onChange={e => setForm(f => ({ ...f, page_id: e.target.value }))} className="admin-input">
                    <option value="">Selecione...</option>
                    {pages.map(p => <option key={p.id} value={p.id}>{p.title} (/{p.slug})</option>)}
                  </select>
                </div>
              ) : (
                <div>
                  <label style={{ fontSize: 12, color: '#aaa', marginBottom: 4, display: 'block' }}>URL</label>
                  <input value={form.url} onChange={e => setForm(f => ({ ...f, url: e.target.value }))} className="admin-input" placeholder="https://..." />
                </div>
              )}
              <div style={{ display: 'flex', gap: 16 }}>
                <label style={{ display: 'flex', alignItems: 'center', gap: 6, color: '#ccc', fontSize: 13, cursor: 'pointer' }}>
                  <input type="checkbox" checked={!!form.is_active} onChange={e => setForm(f => ({ ...f, is_active: e.target.checked ? 1 : 0 }))} style={{ accentColor: '#c9a96e' }} /> Ativo
                </label>
                <label style={{ display: 'flex', alignItems: 'center', gap: 6, color: '#ccc', fontSize: 13, cursor: 'pointer' }}>
                  <input type="checkbox" checked={!!form.open_new_tab} onChange={e => setForm(f => ({ ...f, open_new_tab: e.target.checked ? 1 : 0 }))} style={{ accentColor: '#c9a96e' }} /> Nova aba
                </label>
              </div>
            </div>

            <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 20 }}>
              <button onClick={() => setShowForm(false)} className="admin-btn admin-btn--secondary">Cancelar</button>
              <button onClick={save} className="admin-btn admin-btn--primary"><FiCheck size={14} /> {editing ? 'Salvar' : 'Criar'}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
