import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useSite } from '../contexts/SiteContext';
import { projectsAPI, testimonialsAPI } from '../api/api';
import './Home.css';

const fadeIn = { hidden: { opacity: 0, y: 40 }, visible: { opacity: 1, y: 0, transition: { duration: 0.8 } } };

const DEFAULT_PROJECTS = [
  { id: 1, slug: 'projeto-1', couple_names: 'Mason & Jeff', location: 'Aspen, Colorado', thumbnail_url: 'https://images.unsplash.com/photo-1519741497674-611481863552?w=800&q=80', title: 'Mason & Jeff' },
  { id: 2, slug: 'projeto-2', couple_names: 'McKenzie & Spencer', location: 'Seattle, WA', thumbnail_url: 'https://images.unsplash.com/photo-1606216794074-735e91aa2c92?w=800&q=80', title: 'McKenzie & Spencer' },
  { id: 3, slug: 'projeto-3', couple_names: 'Adriane & Tyler', location: 'Salt Lake City, Utah', thumbnail_url: 'https://images.unsplash.com/photo-1465495976277-4387d4b0b4c6?w=800&q=80', title: 'Adriane & Tyler' },
];

export default function Home() {
  const { getSetting } = useSite();
  const [projects, setProjects] = useState([]);
  const [testimonials, setTestimonials] = useState([]);

  useEffect(() => {
    projectsAPI.getFeatured(6).then(r => {
      const data = r.data.data || [];
      setProjects(data.length > 0 ? data : DEFAULT_PROJECTS);
    }).catch(() => setProjects(DEFAULT_PROJECTS));
    testimonialsAPI.getAll().then(r => setTestimonials(r.data.data || [])).catch(() => {});
  }, []);

  return (
    <div className="home">
      {/* Hero */}
      <section className="home__hero">
        <div className="home__hero-gradient" />
        <motion.div className="home__hero-content" initial="hidden" animate="visible" variants={fadeIn}>
          <p className="home__hero-estd">ESTD <span className="home__hero-monogram">{getSetting('site_name', 'S').charAt(0)}</span> 2022</p>
          <h1 className="home__hero-title">{getSetting('hero_title', getSetting('site_name', 'STORNOWAY'))}</h1>
          <p className="home__hero-subtitle">{getSetting('hero_subtitle', 'FILM HOUSE')}</p>
        </motion.div>
      </section>

      {/* Sobre — seção branca com monograma, título e imagem */}
      <motion.section className="home__about" initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
        <div className="home__about-inner">
          <div className="home__about-monogram">
            <svg width="40" height="50" viewBox="0 0 40 50" fill="none">
              <path d="M20 0 L20 50 M5 10 C5 10 20 0 35 10 M5 40 C5 40 20 50 35 40" stroke="#333" strokeWidth="1" />
              <circle cx="20" cy="25" r="4" fill="none" stroke="#333" strokeWidth="1" />
            </svg>
          </div>
          <h2 className="home__about-title">
            O NOVO PADRÃO EM QUALIDADE <em>PARA</em><br />FILMAGENS DE CASAMENTO
          </h2>
          <div className="home__about-image">
            <img src={getSetting('about_home_image', 'https://images.unsplash.com/photo-1519741497674-611481863552?w=900&q=80')} alt="Casamento elegante" />
          </div>
          <p className="home__about-text">
            {getSetting('about_home_text', 'Nosso objetivo é oferecer filmes de casamento da mais alta qualidade para casais que desejam celebrar seu amor em grande estilo, além de orientar cineastas ambiciosos em sua própria jornada. A experiência vivida desde o contato até a publicação e comercialização do Stortoway, será elevada através cada videcliatesta e conselheiro, focados na construção de relações reais, refinadas e significantes.')}
          </p>
          <Link to="/about" className="home__link">SAIBA MAIS</Link>
        </div>
      </motion.section>

      {/* Fundadores */}
      <motion.section className="home__founders" initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
        <div className="home__founders-inner">
          <div className="home__founders-photo">
            <img src={getSetting('founders_image', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=600&q=80')} alt="Fundadores" />
          </div>
          <div className="home__founders-content">
            <h2 className="home__founders-title">CONHEÇA OS<br /><span>FUNDADORES</span></h2>
            <h3 className="home__founders-names">{getSetting('founders_names', 'JAKE WEISLER E NATE TEAHAN')}</h3>
            <p className="home__founders-text">
              {getSetting('founders_text', 'Considerados entre os 10 melhores videógrafos de casamento nos EUA, Jake e Nate, da Stornoway Films, são muito requisitados por suas abordagens refinadas e intuitivas para registrar histórias, em amor e em maiordomos.')}
            </p>
            <Link to="/about" className="home__btn-outline">SOBRE A EQUIPE</Link>
            <div className="home__founders-featured">
              <p className="home__founders-featured-label">Em destaque</p>
              <div className="home__founders-logos">
                <span className="home__featured-logo">People</span>
                <span className="home__featured-logo home__featured-logo--script">Junebug</span>
                <span className="home__featured-logo">BRIDES</span>
              </div>
            </div>
          </div>
        </div>
      </motion.section>

      {/* Projetos em destaque */}
      <section className="home__projects">
        <motion.div className="home__projects-header" initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
          <p className="home__script-title">Luxo atemporal</p>
          <h2 className="home__section-title">CAPTURANDO SUA HISTÓRIA COM UMA DEDICAÇÃO INTRANSIGENTE À QUALIDADE</h2>
          <p className="home__section-desc">
            Desde o primeiro contato até a entrega do seu filme de casamento, nos comprometemos com a excelência em cada etapa da produção de vídeo do casamento, entregando por último e exclusivo, ou Stortoway e seu experiência de filmes extraordinários.
          </p>
        </motion.div>
        <div className="home__projects-grid">
          {projects.slice(0, 3).map((project, i) => (
            <motion.div key={project.id} className="home__project-card" initial={{ opacity: 0, y: 30 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true }} transition={{ delay: i * 0.15 }}>
              <Link to={`/projects/${project.slug}`}>
                {project.thumbnail_url ? (
                  <img src={project.thumbnail_url} alt={project.title} />
                ) : (
                  <div className="home__project-placeholder" />
                )}
                <div className="home__project-overlay">
                  <span className="home__project-name">
                    {project.couple_names || project.title} – {project.location}
                  </span>
                  <span className="home__project-arrow">▸</span>
                </div>
              </Link>
            </motion.div>
          ))}
        </div>
        <Link to="/projects" className="home__link home__link--dark">MAIS FILMES</Link>
      </section>

      {/* Testimonial / Filme em destaque */}
      <motion.section className="home__testimonial" initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
        <div className="home__testimonial-bg">
          <img src={getSetting('testimonial_bg', 'https://images.unsplash.com/photo-1511285560929-80b456fea0bc?w=1400&q=80')} alt="" />
        </div>
        <div className="home__testimonial-overlay" />
        <div className="home__testimonial-content">
          <p className="home__testimonial-names">
            {testimonials.length > 0 ? testimonials[0].couple_name : 'Dallas e Brayan'}
          </p>
          <blockquote className="home__testimonial-quote">
            {testimonials.length > 0
              ? `"${testimonials[0].content}"`
              : '"NEM SEI POR ONDE COMEÇAR. O TRABALHO DELES FALA POR SI SÓ. TODOS NÓS SENTIMOS TÃO À VONTADE EM FRENTE ÀS CÂMERAS. O VÍDEO QUE ELES CRIARAM FOI UMA OBRA-PRIMA. FOI TÃO PESSOAL PARA A NOSSA HISTÓRIA, NOSSO RELACIONAMENTO E NOSSA JORNADA. EU OS RECOMENDO SEM RESERVAS."'}
          </blockquote>
          <Link to="/projects" className="home__btn-outline home__btn-outline--light">ASSISTA AO FILME</Link>
        </div>
      </motion.section>

      {/* CTA */}
      <motion.section className="home__cta" initial="hidden" whileInView="visible" viewport={{ once: true }} variants={fadeIn}>
        <p className="home__script-title">Vamos registrar a sua história.</p>
        <h2 className="home__cta-title">VIVA UM FILME DE CASAMENTO TÃO INESQUECÍVEL QUANTO O SEU AMOR.</h2>
        <Link to="/contact" className="home__btn-solid">CONECTE-SE HOJE</Link>
      </motion.section>
    </div>
  );
}
