import React, { useState, useEffect, useCallback } from 'react';
import { useDropzone } from 'react-dropzone';
import { FiUpload, FiX, FiSearch, FiCheck, FiImage, FiFilm, FiTrash2, FiFolder } from 'react-icons/fi';
import { toast } from 'react-toastify';
import { mediaAPI } from '../api/api';

export default function MediaPicker({ type = 'all', onSelect, onClose }) {
  const [files, setFiles] = useState([]);
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState(type === 'all' ? '' : type);
  const [loading, setLoading] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);

  const loadMedia = useCallback(async () => {
    setLoading(true);
    try {
      const params = { page, per_page: 20 };
      if (filter) params.type = filter;
      if (search) params.search = search;
      const res = await mediaAPI.getAll(params);
      setFiles(res.data.data || []);
      setTotal(res.data.pagination?.total || 0);
    } catch {
      toast.error('Erro ao carregar mídia');
    } finally {
      setLoading(false);
    }
  }, [page, filter, search]);

  useEffect(() => {
    loadMedia();
  }, [loadMedia]);

  const onDrop = useCallback(async (acceptedFiles) => {
    if (acceptedFiles.length === 0) return;
    setUploading(true);
    try {
      for (const file of acceptedFiles) {
        const formData = new FormData();
        formData.append('file', file);
        await mediaAPI.upload(formData);
      }
      toast.success(`${acceptedFiles.length} arquivo(s) enviado(s)!`);
      loadMedia();
    } catch {
      toast.error('Erro no upload');
    } finally {
      setUploading(false);
    }
  }, [loadMedia]);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: type === 'image'
      ? { 'image/*': ['.jpg', '.jpeg', '.png', '.gif', '.webp', '.avif'] }
      : type === 'video'
        ? { 'video/*': ['.mp4', '.webm', '.mov'] }
        : { 'image/*': [], 'video/*': [] },
    maxSize: 500 * 1024 * 1024
  });

  const apiBaseUrl = process.env.REACT_APP_API_URL || '/api';
  const getFileUrl = (file) => {
    if (file.file_path) {
      return `${apiBaseUrl}/uploads/${file.file_path}`;
    }
    return file.url || '';
  };

  return (
    <div className="media-picker-overlay" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="media-picker">
        <div className="mp-header">
          <h3>Biblioteca de Mídia</h3>
          <button onClick={onClose} className="mp-close"><FiX size={20} /></button>
        </div>

        {/* Upload Area */}
        <div {...getRootProps()} className={`mp-dropzone ${isDragActive ? 'mp-dropzone--active' : ''}`}>
          <input {...getInputProps()} />
          {uploading ? (
            <p>Enviando...</p>
          ) : isDragActive ? (
            <p>Solte os arquivos aqui...</p>
          ) : (
            <p><FiUpload size={20} /> Arraste arquivos ou clique para enviar</p>
          )}
        </div>

        {/* Filters */}
        <div className="mp-filters">
          <div className="mp-search">
            <FiSearch size={14} />
            <input value={search} onChange={e => { setSearch(e.target.value); setPage(1); }} placeholder="Buscar..." />
          </div>
          <div className="mp-type-filter">
            <button className={!filter ? 'active' : ''} onClick={() => { setFilter(''); setPage(1); }}>Todos</button>
            <button className={filter === 'image' ? 'active' : ''} onClick={() => { setFilter('image'); setPage(1); }}><FiImage size={12} /> Imagens</button>
            <button className={filter === 'video' ? 'active' : ''} onClick={() => { setFilter('video'); setPage(1); }}><FiFilm size={12} /> Vídeos</button>
          </div>
        </div>

        {/* Grid */}
        <div className="mp-grid">
          {loading ? (
            <div className="mp-loading">Carregando...</div>
          ) : files.length === 0 ? (
            <div className="mp-empty">Nenhuma mídia encontrada</div>
          ) : (
            files.map(file => (
              <div key={file.id} className="mp-item" onClick={() => onSelect(getFileUrl(file))}>
                {file.file_type === 'image' ? (
                  <img src={file.thumbnail_path ? `${apiBaseUrl}/uploads/${file.thumbnail_path}` : getFileUrl(file)} alt={file.original_name} />
                ) : (
                  <div className="mp-item__video">
                    <FiFilm size={24} />
                    <span>{file.original_name}</span>
                  </div>
                )}
                <div className="mp-item__overlay">
                  <FiCheck size={20} />
                </div>
              </div>
            ))
          )}
        </div>

        {/* Pagination */}
        {total > 20 && (
          <div className="mp-pagination">
            <button disabled={page <= 1} onClick={() => setPage(p => p - 1)}>Anterior</button>
            <span>Página {page} de {Math.ceil(total / 20)}</span>
            <button disabled={page >= Math.ceil(total / 20)} onClick={() => setPage(p => p + 1)}>Próxima</button>
          </div>
        )}
      </div>
    </div>
  );
}
