import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useSite } from '../contexts/SiteContext';
import './IntroAnimation.css';

export default function IntroAnimation({ onComplete }) {
  const { getSetting } = useSite();
  const [phase, setPhase] = useState('logo'); // logo -> text -> fadeout

  const introText = getSetting('intro_text', 'STORNOWAY');
  const introSubtitle = getSetting('intro_subtitle', 'FILM HOUSE');
  const introLogo = getSetting('intro_logo');
  const isEnabled = getSetting('intro_enabled', 'true') === 'true';

  useEffect(() => {
    if (!isEnabled) {
      onComplete();
      return;
    }

    const timer1 = setTimeout(() => setPhase('text'), 1200);
    const timer2 = setTimeout(() => setPhase('fadeout'), 3500);
    const timer3 = setTimeout(() => onComplete(), 4500);

    return () => {
      clearTimeout(timer1);
      clearTimeout(timer2);
      clearTimeout(timer3);
    };
  }, [isEnabled, onComplete]);

  if (!isEnabled) return null;

  return (
    <AnimatePresence>
      {phase !== 'done' && (
        <motion.div
          className="intro-overlay"
          initial={{ opacity: 1 }}
          animate={{ opacity: phase === 'fadeout' ? 0 : 1 }}
          transition={{ duration: 1 }}
        >
          <div className="intro-content">
            {/* Logo ou ícone inicial */}
            <motion.div
              className="intro-logo-container"
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ duration: 0.8, ease: 'easeOut' }}
            >
              {introLogo ? (
                <img src={introLogo} alt="" className="intro-logo-img" />
              ) : (
                <div className="intro-monogram">
                  {introText.charAt(0)}
                </div>
              )}
            </motion.div>

            {/* Nome / Texto */}
            <motion.div
              className="intro-text-container"
              initial={{ opacity: 0, y: 30 }}
              animate={{ 
                opacity: phase === 'logo' ? 0 : 1, 
                y: phase === 'logo' ? 30 : 0 
              }}
              transition={{ duration: 0.8, ease: 'easeOut' }}
            >
              <h1 className="intro-title">{introText}</h1>
              {introSubtitle && (
                <motion.p
                  className="intro-subtitle"
                  initial={{ opacity: 0, letterSpacing: '0.3em' }}
                  animate={{ 
                    opacity: phase !== 'logo' ? 1 : 0, 
                    letterSpacing: '0.5em' 
                  }}
                  transition={{ duration: 0.6, delay: 0.3 }}
                >
                  {introSubtitle}
                </motion.p>
              )}
            </motion.div>

            {/* Linha decorativa */}
            <motion.div
              className="intro-line"
              initial={{ width: 0 }}
              animate={{ width: phase !== 'logo' ? 120 : 0 }}
              transition={{ duration: 0.8, delay: 0.5 }}
            />
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}
