import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { FiFileText, FiFilm, FiImage, FiMail } from 'react-icons/fi';
import { pagesAPI, projectsAPI, mediaAPI, contactAPI } from '../api/api';

export default function Dashboard() {
  const [stats, setStats] = useState({ pages: 0, projects: 0, media: 0, contacts: 0, unread: 0 });

  useEffect(() => {
    Promise.all([
      pagesAPI.getAll().catch(() => ({ data: { data: [] } })),
      projectsAPI.getAll().catch(() => ({ data: { data: [] } })),
      mediaAPI.getAll().catch(() => ({ data: { data: [] } })),
      contactAPI.getAll().catch(() => ({ data: { data: [], unread_count: 0 } })),
    ]).then(([pages, projects, media, contacts]) => {
      setStats({
        pages: pages.data.data?.length || 0,
        projects: projects.data.data?.length || 0,
        media: media.data.pagination?.total || media.data.data?.length || 0,
        contacts: contacts.data.pagination?.total || contacts.data.data?.length || 0,
        unread: contacts.data.unread_count || 0,
      });
    });
  }, []);

  const cards = [
    { icon: FiFileText, label: 'Páginas', count: stats.pages, link: '/admin/pages', color: '#4A90D9' },
    { icon: FiFilm, label: 'Projetos', count: stats.projects, link: '/admin/projects', color: '#E67E22' },
    { icon: FiImage, label: 'Mídias', count: stats.media, link: '/admin/media', color: '#27AE60' },
    { icon: FiMail, label: 'Contatos', count: stats.contacts, link: '/admin/contacts', color: '#E74C3C', badge: stats.unread },
  ];

  return (
    <div>
      <div className="admin-page-header">
        <h1>Dashboard</h1>
      </div>

      <div className="admin-grid admin-grid--4">
        {cards.map(card => (
          <Link key={card.label} to={card.link} style={{ textDecoration: 'none' }}>
            <div className="admin-card" style={{ textAlign: 'center', position: 'relative' }}>
              {card.badge > 0 && (
                <span style={{ position: 'absolute', top: 12, right: 12, background: '#E74C3C', color: '#fff', borderRadius: '50%', width: 22, height: 22, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.65rem', fontWeight: 700 }}>{card.badge}</span>
              )}
              <card.icon size={28} color={card.color} style={{ marginBottom: 12 }} />
              <div className="admin-stat__number">{card.count}</div>
              <div className="admin-stat__label">{card.label}</div>
            </div>
          </Link>
        ))}
      </div>

      <div className="admin-grid admin-grid--2" style={{ marginTop: 24 }}>
        <div className="admin-card">
          <h3 style={{ fontSize: '0.9rem', marginBottom: 16 }}>Ações Rápidas</h3>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            <Link to="/admin/pages" className="admin-btn admin-btn--primary" style={{ justifyContent: 'center' }}>Editar Páginas</Link>
            <Link to="/admin/projects" className="admin-btn admin-btn--secondary" style={{ justifyContent: 'center' }}>Gerenciar Projetos</Link>
            <Link to="/admin/media" className="admin-btn admin-btn--secondary" style={{ justifyContent: 'center' }}>Biblioteca de Mídia</Link>
            <Link to="/admin/settings" className="admin-btn admin-btn--secondary" style={{ justifyContent: 'center' }}>Configurações do Site</Link>
          </div>
        </div>
        <div className="admin-card">
          <h3 style={{ fontSize: '0.9rem', marginBottom: 16 }}>Informações</h3>
          <div style={{ fontSize: '0.8rem', color: '#666', lineHeight: 1.8 }}>
            <p>Bem-vindo ao painel administrativo do seu site.</p>
            <p>Use o menu lateral para navegar entre as seções.</p>
            <p><strong>Editor Visual:</strong> Acesse "Páginas" para usar o editor visual completo com arrastar e soltar.</p>
            <p><strong>Mídia:</strong> Faça upload e gerencie todos os seus vídeos e imagens.</p>
          </div>
        </div>
      </div>
    </div>
  );
}
