import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import ReactPlayer from 'react-player';
import { projectsAPI } from '../api/api';

export default function ProjectDetail() {
  const { slug } = useParams();
  const [project, setProject] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    projectsAPI.getBySlug(slug)
      .then(r => setProject(r.data.data))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [slug]);

  if (loading) return <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', paddingTop: 80 }}>Carregando...</div>;
  if (!project) return <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', paddingTop: 80 }}>Projeto não encontrado</div>;

  return (
    <div style={{ paddingTop: 80 }}>
      {/* Hero */}
      <section style={{ position: 'relative', height: '50vh', background: '#1a1a2e', display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden' }}>
        {project.thumbnail_url && (
          <>
            <img src={project.thumbnail_url} alt="" style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', objectFit: 'cover', opacity: 0.4 }} />
            <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.3)' }} />
          </>
        )}
        <motion.div style={{ position: 'relative', zIndex: 2, textAlign: 'center', color: '#fff' }} initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }}>
          <h1 style={{ fontFamily: "'Great Vibes', cursive", fontSize: '3rem', marginBottom: 8 }}>{project.couple_names || project.title}</h1>
          <p style={{ fontFamily: "'Montserrat', sans-serif", fontSize: '0.7rem', letterSpacing: '0.3em', opacity: 0.7 }}>{project.location}</p>
        </motion.div>
      </section>

      {/* Vídeo principal */}
      {(project.video_url || project.video_embed) && (
        <section style={{ maxWidth: 900, margin: '60px auto', padding: '0 20px' }}>
          <div style={{ position: 'relative', paddingBottom: '56.25%', height: 0 }}>
            {project.video_embed ? (
              <div dangerouslySetInnerHTML={{ __html: project.video_embed }} style={{ position: 'absolute', inset: 0 }} />
            ) : (
              <ReactPlayer url={project.video_url} width="100%" height="100%" controls style={{ position: 'absolute', top: 0, left: 0 }} />
            )}
          </div>
        </section>
      )}

      {/* Descrição */}
      {project.description && (
        <motion.section style={{ maxWidth: 700, margin: '40px auto 60px', padding: '0 20px', textAlign: 'center' }} initial={{ opacity: 0 }} whileInView={{ opacity: 1 }} viewport={{ once: true }}>
          <p style={{ fontFamily: "'Montserrat', sans-serif", fontSize: '0.85rem', lineHeight: 1.9, color: '#666' }}>{project.description}</p>
        </motion.section>
      )}

      {/* Galeria */}
      {project.gallery && project.gallery.length > 0 && (
        <section style={{ maxWidth: 1000, margin: '0 auto 80px', padding: '0 20px' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: 16 }}>
            {project.gallery.map((item, i) => (
              <motion.div key={i} initial={{ opacity: 0 }} whileInView={{ opacity: 1 }} transition={{ delay: i * 0.1 }} style={{ overflow: 'hidden' }}>
                <img src={item.url || item} alt="" style={{ width: '100%', height: 250, objectFit: 'cover' }} />
              </motion.div>
            ))}
          </div>
        </section>
      )}

      {/* Depoimentos do projeto */}
      {project.testimonials?.length > 0 && (
        <section style={{ background: '#1a1a2e', padding: '80px 40px', textAlign: 'center', color: '#fff' }}>
          {project.testimonials.map(t => (
            <div key={t.id} style={{ maxWidth: 600, margin: '0 auto' }}>
              <p style={{ fontFamily: "'Great Vibes', cursive", fontSize: '1.5rem', color: '#d4af37', marginBottom: 16 }}>{t.client_name}</p>
              <blockquote style={{ fontFamily: "'Montserrat', sans-serif", fontSize: '0.8rem', lineHeight: 1.8, fontStyle: 'italic', opacity: 0.9 }}>"{t.content}"</blockquote>
            </div>
          ))}
        </section>
      )}

      {/* Voltar */}
      <div style={{ textAlign: 'center', padding: '40px 20px 80px' }}>
        <Link to="/projects" style={{ fontFamily: "'Montserrat', sans-serif", fontSize: '0.7rem', letterSpacing: '0.2em', color: '#333', textDecoration: 'none', borderBottom: '1px solid #333', paddingBottom: 4 }}>
          ← VOLTAR AOS PROJETOS
        </Link>
      </div>
    </div>
  );
}
