import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { DndContext, closestCenter, PointerSensor, useSensor, useSensors, DragOverlay } from '@dnd-kit/core';
import { SortableContext, verticalListSortingStrategy, useSortable, arrayMove } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { toast } from 'react-toastify';
import { FiPlus, FiTrash2, FiMove, FiEye, FiEyeOff, FiChevronDown, FiChevronUp, FiSave, FiArrowLeft, FiEdit3, FiImage, FiFilm, FiType, FiGrid, FiMessageSquare, FiMousePointer, FiCopy, FiMaximize2, FiMinimize2 } from 'react-icons/fi';
import { pagesAPI, sectionsAPI } from '../api/api';
import SectionEditor from './SectionEditor';
import './PageBuilder.css';

const SECTION_TYPES = [
  { type: 'hero', label: 'Hero / Banner', icon: FiImage, desc: 'Banner principal com vídeo ou imagem', color: '#e74c3c' },
  { type: 'text', label: 'Texto', icon: FiType, desc: 'Bloco de texto com título', color: '#3498db' },
  { type: 'image', label: 'Imagem', icon: FiImage, desc: 'Imagem com legenda e link', color: '#2ecc71' },
  { type: 'video', label: 'Vídeo', icon: FiFilm, desc: 'Player de vídeo', color: '#9b59b6' },
  { type: 'gallery', label: 'Galeria', icon: FiGrid, desc: 'Grade de imagens/vídeos', color: '#f39c12' },
  { type: 'testimonial', label: 'Depoimento', icon: FiMessageSquare, desc: 'Citação de cliente', color: '#1abc9c' },
  { type: 'cta', label: 'Call to Action', icon: FiMousePointer, desc: 'Seção com botão de ação', color: '#e67e22' },
  { type: 'founders', label: 'Fundadores', icon: FiType, desc: 'Seção Sobre com foto', color: '#c9a96e' },
  { type: 'projects_grid', label: 'Grade Projetos', icon: FiGrid, desc: 'Lista projetos em destaque', color: '#34495e' },
  { type: 'services_list', label: 'Lista Serviços', icon: FiGrid, desc: 'Lista serviços cadastrados', color: '#16a085' },
  { type: 'contact_form', label: 'Formulário Contato', icon: FiEdit3, desc: 'Formulário de contato', color: '#2980b9' },
  { type: 'custom', label: 'HTML Personalizado', icon: FiType, desc: 'Código HTML/CSS customizado', color: '#8e44ad' },
];

function SectionPreview({ section }) {
  const typeInfo = SECTION_TYPES.find(t => t.type === section.section_type) || {};
  const content = section.content || {};
  const styles = section.styles || {};

  switch (section.section_type) {
    case 'hero':
      return (
        <div className="pb-preview-block pb-preview-block--hero" style={{ backgroundImage: content.background_image ? `url(${content.background_image})` : undefined }}>
          <div className="pb-preview-block__overlay">
            {content.monogram && <span className="pb-preview-block__monogram">{content.monogram}</span>}
            <h3>{content.title || 'Hero Banner'}</h3>
            {content.subtitle && <p>{content.subtitle}</p>}
            {content.button_text && <span className="pb-preview-block__btn">{content.button_text}</span>}
          </div>
        </div>
      );
    case 'text':
      return (
        <div className="pb-preview-block pb-preview-block--text" style={{ textAlign: content.alignment || 'center' }}>
          <h3>{content.title || 'Bloco de Texto'}</h3>
          <p>{content.body ? content.body.substring(0, 120) + (content.body.length > 120 ? '...' : '') : 'Adicione seu texto aqui...'}</p>
        </div>
      );
    case 'image':
      return (
        <div className="pb-preview-block pb-preview-block--image">
          {content.url ? <img src={content.url} alt={content.alt || ''} /> : <div className="pb-preview-block__placeholder"><FiImage size={32} /><span>Selecione uma imagem</span></div>}
          {content.caption && <p className="pb-preview-block__caption">{content.caption}</p>}
        </div>
      );
    case 'video':
      return (
        <div className="pb-preview-block pb-preview-block--video">
          {content.poster ? <img src={content.poster} alt="" /> : <div className="pb-preview-block__placeholder"><FiFilm size={32} /><span>{content.url || 'Adicione um vídeo'}</span></div>}
          <div className="pb-preview-block__play">▶</div>
        </div>
      );
    case 'gallery':
      return (
        <div className="pb-preview-block pb-preview-block--gallery">
          <h3>{content.title || 'Galeria'}</h3>
          <div className="pb-preview-block__gallery-grid" style={{ gridTemplateColumns: `repeat(${content.columns || 3}, 1fr)` }}>
            {(content.items || []).slice(0, 6).map((item, i) => (
              <div key={i} className="pb-preview-block__gallery-item">
                <img src={item.url} alt="" />
              </div>
            ))}
            {(!content.items || content.items.length === 0) && <div className="pb-preview-block__placeholder" style={{ gridColumn: '1 / -1' }}><FiGrid size={24} /><span>{content.columns || 3} colunas</span></div>}
          </div>
        </div>
      );
    case 'testimonial':
      return (
        <div className="pb-preview-block pb-preview-block--testimonial" style={{ backgroundImage: content.background_image ? `url(${content.background_image})` : undefined }}>
          <div className="pb-preview-block__overlay">
            <blockquote>"{content.quote || 'Depoimento do cliente...'}"</blockquote>
            <cite>— {content.author || 'Nome do casal'}</cite>
          </div>
        </div>
      );
    case 'cta':
      return (
        <div className="pb-preview-block pb-preview-block--cta">
          <h3>{content.title || 'Call to Action'}</h3>
          {content.subtitle && <p>{content.subtitle}</p>}
          {content.button_text && <span className="pb-preview-block__btn">{content.button_text}</span>}
        </div>
      );
    case 'founders':
      return (
        <div className="pb-preview-block pb-preview-block--founders">
          <div className="pb-preview-block__founders-grid">
            {content.image ? <img src={content.image} alt="" /> : <div className="pb-preview-block__placeholder"><FiImage size={24} /></div>}
            <div className="pb-preview-block__founders-info">
              <h3>{content.title || 'Fundadores'}</h3>
              <strong>{content.name || 'Nome'}</strong>
              <p>{content.bio ? content.bio.substring(0, 80) + '...' : 'Bio...'}</p>
            </div>
          </div>
        </div>
      );
    case 'projects_grid':
      return (
        <div className="pb-preview-block pb-preview-block--projects">
          <h3>{content.title || 'Projetos'}</h3>
          <div className="pb-preview-block__projects-row">
            {[1,2,3].map(i => <div key={i} className="pb-preview-block__project-thumb" />)}
          </div>
          <span className="pb-preview-block__meta">Exibindo até {content.limit || 6} projetos</span>
        </div>
      );
    case 'services_list':
      return (
        <div className="pb-preview-block pb-preview-block--services">
          <h3>{content.title || 'Serviços'}</h3>
          <div className="pb-preview-block__projects-row">
            {[1,2,3].map(i => <div key={i} className="pb-preview-block__project-thumb" />)}
          </div>
        </div>
      );
    case 'contact_form':
      return (
        <div className="pb-preview-block pb-preview-block--contact">
          <h3>{content.title || 'Formulário de Contato'}</h3>
          <div className="pb-preview-block__form-mock">
            <div className="pb-preview-block__input-mock" />
            <div className="pb-preview-block__input-mock" />
            <div className="pb-preview-block__input-mock pb-preview-block__input-mock--tall" />
            <span className="pb-preview-block__btn">Enviar</span>
          </div>
        </div>
      );
    case 'custom':
      return (
        <div className="pb-preview-block pb-preview-block--custom">
          <FiType size={20} />
          <span>HTML Personalizado</span>
          {content.html && <code>{content.html.substring(0, 60)}...</code>}
        </div>
      );
    default:
      return (
        <div className="pb-preview-block">
          <span>{typeInfo.label || section.section_type}</span>
        </div>
      );
  }
}

function InlineAddButton({ onAdd }) {
  const [showMenu, setShowMenu] = useState(false);
  return (
    <div className="pb-inline-add">
      <div className="pb-inline-add__line" />
      <button className="pb-inline-add__btn" onClick={() => setShowMenu(!showMenu)} title="Inserir seção aqui">
        <FiPlus size={14} />
      </button>
      <div className="pb-inline-add__line" />
      {showMenu && (
        <div className="pb-inline-add__menu">
          {SECTION_TYPES.map(st => (
            <button key={st.type} className="pb-inline-add__type" onClick={() => { onAdd(st.type); setShowMenu(false); }}>
              <st.icon size={14} style={{ color: st.color }} />
              <span>{st.label}</span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

function SortableSection({ section, isEditing, isExpanded, onEdit, onDelete, onToggle, onUpdate, onDuplicate, onExpand }) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({ id: section.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.4 : 1,
    zIndex: isDragging ? 100 : 1,
  };

  const typeInfo = SECTION_TYPES.find(t => t.type === section.section_type) || { label: section.section_type, icon: FiType, color: '#888' };
  const Icon = typeInfo.icon;

  return (
    <div ref={setNodeRef} style={style} className={`pb-section ${!section.is_active ? 'pb-section--hidden' : ''} ${isEditing ? 'pb-section--editing' : ''} ${isDragging ? 'pb-section--dragging' : ''}`}>
      <div className="pb-section__header">
        <button className="pb-section__drag" {...attributes} {...listeners} title="Arrastar para reordenar">
          <FiMove size={16} />
        </button>
        <div className="pb-section__type-badge" style={{ background: typeInfo.color }}>
          <Icon size={12} />
        </div>
        <span className="pb-section__type">{typeInfo.label}</span>
        <span className="pb-section__title">{section.content?.title || ''}</span>
        <div className="pb-section__actions">
          <button onClick={() => onToggle(section.id)} title={section.is_active ? 'Ocultar' : 'Mostrar'}>
            {section.is_active ? <FiEye size={14} /> : <FiEyeOff size={14} />}
          </button>
          <button onClick={() => onExpand(section.id)} title={isExpanded ? 'Minimizar preview' : 'Expandir preview'}>
            {isExpanded ? <FiMinimize2 size={14} /> : <FiMaximize2 size={14} />}
          </button>
          <button onClick={() => onDuplicate(section)} title="Duplicar">
            <FiCopy size={14} />
          </button>
          <button onClick={() => onEdit(section.id)} title="Editar" className={isEditing ? 'pb-section__btn--active' : ''}>
            <FiEdit3 size={14} />
          </button>
          <button onClick={() => onDelete(section.id)} title="Excluir" className="pb-section__delete">
            <FiTrash2 size={14} />
          </button>
        </div>
      </div>

      {/* Preview visual do bloco */}
      {isExpanded && !isEditing && (
        <div className="pb-section__preview" onClick={() => onEdit(section.id)}>
          <SectionPreview section={section} />
        </div>
      )}

      {isEditing && (
        <div className="pb-section__editor">
          <SectionEditor
            section={section}
            onUpdate={(data) => onUpdate(section.id, data)}
          />
        </div>
      )}
    </div>
  );
}

export default function PageBuilder() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [pages, setPages] = useState([]);
  const [selectedPage, setSelectedPage] = useState(null);
  const [sections, setSections] = useState([]);
  const [editingSection, setEditingSection] = useState(null);
  const [expandedSections, setExpandedSections] = useState(new Set());
  const [showAddPanel, setShowAddPanel] = useState(false);
  const [showPreview, setShowPreview] = useState(false);
  const [saving, setSaving] = useState(false);
  const [showNewPage, setShowNewPage] = useState(false);
  const [newPageTitle, setNewPageTitle] = useState('');
  const [activeDragId, setActiveDragId] = useState(null);

  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 5 } })
  );

  useEffect(() => {
    pagesAPI.getAll().then(r => {
      setPages(r.data.data || []);
      if (id) {
        loadPage(id);
      }
    }).catch(() => {});
  }, [id]);

  const loadPage = useCallback(async (pageId) => {
    try {
      const res = await pagesAPI.getById(pageId);
      setSelectedPage(res.data.data);
      setSections(res.data.data.sections || []);
      setEditingSection(null);
    } catch {
      toast.error('Erro ao carregar página');
    }
  }, []);

  const selectPage = (page) => {
    navigate(`/admin/pages/${page.id}`);
  };

  const createPage = async () => {
    if (!newPageTitle.trim()) return;
    try {
      const res = await pagesAPI.create({ title: newPageTitle, is_published: 0 });
      toast.success('Página criada!');
      setShowNewPage(false);
      setNewPageTitle('');
      const pagesRes = await pagesAPI.getAll();
      setPages(pagesRes.data.data || []);
      navigate(`/admin/pages/${res.data.data.id}`);
    } catch {
      toast.error('Erro ao criar página');
    }
  };

  const savePage = async () => {
    if (!selectedPage) return;
    setSaving(true);
    try {
      await pagesAPI.update(selectedPage.id, {
        title: selectedPage.title,
        is_published: selectedPage.is_published,
        meta_description: selectedPage.meta_description
      });

      // Salvar ordem das seções
      const order = sections.map(s => s.id);
      await sectionsAPI.reorderPage(selectedPage.id, { order });

      toast.success('Página salva!');
    } catch {
      toast.error('Erro ao salvar');
    } finally {
      setSaving(false);
    }
  };

  const addSection = async (type, afterIndex = null) => {
    if (!selectedPage) return;
    try {
      const res = await sectionsAPI.createForPage(selectedPage.id, { section_type: type });
      const newSection = res.data.data;
      setSections(prev => {
        if (afterIndex !== null) {
          const updated = [...prev];
          updated.splice(afterIndex + 1, 0, newSection);
          return updated;
        }
        return [...prev, newSection];
      });
      setShowAddPanel(false);
      setEditingSection(newSection.id);
      setExpandedSections(prev => new Set([...prev, newSection.id]));
      toast.success('Seção adicionada!');
    } catch {
      toast.error('Erro ao adicionar seção');
    }
  };

  const duplicateSection = async (section) => {
    if (!selectedPage) return;
    try {
      const res = await sectionsAPI.createForPage(selectedPage.id, {
        section_type: section.section_type,
        content: section.content,
        styles: section.styles
      });
      const idx = sections.findIndex(s => s.id === section.id);
      setSections(prev => {
        const updated = [...prev];
        updated.splice(idx + 1, 0, res.data.data);
        return updated;
      });
      toast.success('Seção duplicada!');
    } catch {
      toast.error('Erro ao duplicar seção');
    }
  };

  const toggleExpand = (sectionId) => {
    setExpandedSections(prev => {
      const next = new Set(prev);
      if (next.has(sectionId)) next.delete(sectionId);
      else next.add(sectionId);
      return next;
    });
  };

  const expandAll = () => {
    setExpandedSections(new Set(sections.map(s => s.id)));
  };

  const collapseAll = () => {
    setExpandedSections(new Set());
  };

  const updateSection = async (sectionId, data) => {
    try {
      await sectionsAPI.update(sectionId, data);
      setSections(prev => prev.map(s => s.id === sectionId ? { ...s, ...data } : s));
      toast.success('Seção atualizada!');
    } catch {
      toast.error('Erro ao atualizar seção');
    }
  };

  const deleteSection = async (sectionId) => {
    if (!window.confirm('Excluir esta seção?')) return;
    try {
      await sectionsAPI.delete(sectionId);
      setSections(prev => prev.filter(s => s.id !== sectionId));
      if (editingSection === sectionId) setEditingSection(null);
      toast.success('Seção excluída!');
    } catch {
      toast.error('Erro ao excluir seção');
    }
  };

  const toggleSection = async (sectionId) => {
    const section = sections.find(s => s.id === sectionId);
    if (!section) return;
    const isActive = section.is_active ? 0 : 1;
    await updateSection(sectionId, { is_active: isActive });
  };

  const handleDragStart = (event) => {
    setActiveDragId(event.active.id);
  };

  const handleDragEnd = (event) => {
    setActiveDragId(null);
    const { active, over } = event;
    if (!over || active.id === over.id) return;

    setSections(prev => {
      const oldIndex = prev.findIndex(s => s.id === active.id);
      const newIndex = prev.findIndex(s => s.id === over.id);
      return arrayMove(prev, oldIndex, newIndex);
    });
  };

  const draggedSection = activeDragId ? sections.find(s => s.id === activeDragId) : null;

  return (
    <div className="page-builder">
      <div className="pb-header">
        <div className="pb-header__left">
          <button onClick={() => navigate('/admin/pages')} className="admin-btn admin-btn--secondary admin-btn--small">
            <FiArrowLeft size={14} /> Páginas
          </button>
          {selectedPage && (
            <div className="pb-header__page-info">
              <input
                value={selectedPage.title}
                onChange={e => setSelectedPage(p => ({ ...p, title: e.target.value }))}
                className="pb-header__title-input"
              />
              <label className="pb-header__publish">
                <input
                  type="checkbox"
                  checked={!!selectedPage.is_published}
                  onChange={e => setSelectedPage(p => ({ ...p, is_published: e.target.checked ? 1 : 0 }))}
                />
                Publicada
              </label>
            </div>
          )}
        </div>
        <div className="pb-header__right">
          {selectedPage && (
            <>
              <button onClick={() => setShowPreview(!showPreview)} className="admin-btn admin-btn--secondary admin-btn--small">
                <FiEye size={14} /> {showPreview ? 'Editor' : 'Preview'}
              </button>
              <button onClick={savePage} disabled={saving} className="admin-btn admin-btn--primary admin-btn--small">
                <FiSave size={14} /> {saving ? 'Salvando...' : 'Salvar'}
              </button>
            </>
          )}
        </div>
      </div>

      <div className="pb-content">
        {/* Lista de páginas */}
        {!selectedPage && (
          <div className="pb-pages">
            <div className="admin-page-header">
              <h1>Páginas</h1>
              <button onClick={() => setShowNewPage(true)} className="admin-btn admin-btn--primary">
                <FiPlus size={16} /> Nova Página
              </button>
            </div>

            {showNewPage && (
              <div className="admin-card" style={{ display: 'flex', gap: 12, alignItems: 'center', marginBottom: 16 }}>
                <input
                  value={newPageTitle}
                  onChange={e => setNewPageTitle(e.target.value)}
                  placeholder="Nome da nova página"
                  className="admin-input"
                  onKeyDown={e => e.key === 'Enter' && createPage()}
                  autoFocus
                />
                <button onClick={createPage} className="admin-btn admin-btn--primary admin-btn--small">Criar</button>
                <button onClick={() => setShowNewPage(false)} className="admin-btn admin-btn--secondary admin-btn--small">Cancelar</button>
              </div>
            )}

            <div className="admin-card">
              <table className="admin-table">
                <thead>
                  <tr>
                    <th>Título</th>
                    <th>Slug</th>
                    <th>Seções</th>
                    <th>Status</th>
                    <th>Ações</th>
                  </tr>
                </thead>
                <tbody>
                  {pages.map(page => (
                    <tr key={page.id}>
                      <td><strong>{page.title}</strong></td>
                      <td style={{ color: '#888' }}>/{page.slug}</td>
                      <td>{page.section_count || 0}</td>
                      <td>
                        <span className={`admin-badge ${page.is_published ? 'admin-badge--success' : 'admin-badge--warning'}`}>
                          {page.is_published ? 'Publicada' : 'Rascunho'}
                        </span>
                      </td>
                      <td>
                        <button onClick={() => selectPage(page)} className="admin-btn admin-btn--primary admin-btn--small">
                          <FiEdit3 size={12} /> Editar
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Editor de página */}
        {selectedPage && !showPreview && (
          <div className="pb-editor">
            <div className="pb-editor__toolbar">
              <span className="pb-editor__count">{sections.length} {sections.length === 1 ? 'seção' : 'seções'}</span>
              <div className="pb-editor__toolbar-btns">
                <button onClick={expandAll} className="admin-btn admin-btn--secondary admin-btn--small" title="Expandir todos">
                  <FiMaximize2 size={12} /> Expandir
                </button>
                <button onClick={collapseAll} className="admin-btn admin-btn--secondary admin-btn--small" title="Minimizar todos">
                  <FiMinimize2 size={12} /> Minimizar
                </button>
              </div>
            </div>

            <div className="pb-editor__sections">
              <DndContext sensors={sensors} collisionDetection={closestCenter} onDragStart={handleDragStart} onDragEnd={handleDragEnd}>
                <SortableContext items={sections.map(s => s.id)} strategy={verticalListSortingStrategy}>
                  {sections.map((section, index) => (
                    <React.Fragment key={section.id}>
                      {index === 0 && <InlineAddButton onAdd={(type) => addSection(type, -1)} />}
                      <SortableSection
                        section={section}
                        isEditing={editingSection === section.id}
                        isExpanded={expandedSections.has(section.id)}
                        onEdit={(id) => setEditingSection(editingSection === id ? null : id)}
                        onDelete={deleteSection}
                        onToggle={toggleSection}
                        onUpdate={updateSection}
                        onDuplicate={duplicateSection}
                        onExpand={toggleExpand}
                      />
                      <InlineAddButton onAdd={(type) => addSection(type, index)} />
                    </React.Fragment>
                  ))}
                </SortableContext>

                <DragOverlay>
                  {draggedSection && (
                    <div className="pb-section pb-section--drag-overlay">
                      <div className="pb-section__header">
                        <FiMove size={16} />
                        <div className="pb-section__type-badge" style={{ background: (SECTION_TYPES.find(t => t.type === draggedSection.section_type) || {}).color }}>
                          {React.createElement((SECTION_TYPES.find(t => t.type === draggedSection.section_type) || { icon: FiType }).icon, { size: 12 })}
                        </div>
                        <span className="pb-section__type">{(SECTION_TYPES.find(t => t.type === draggedSection.section_type) || {}).label}</span>
                        <span className="pb-section__title">{draggedSection.content?.title || ''}</span>
                      </div>
                    </div>
                  )}
                </DragOverlay>
              </DndContext>

              {sections.length === 0 && (
                <div className="pb-empty">
                  <FiPlus size={32} style={{ marginBottom: 12, opacity: 0.4 }} />
                  <p>Nenhuma seção ainda.</p>
                  <p style={{ fontSize: 12 }}>Clique em "Adicionar Seção" abaixo para começar.</p>
                </div>
              )}

              {/* Botão adicionar no final */}
              <div className="pb-add-section">
                <button onClick={() => setShowAddPanel(!showAddPanel)} className="pb-add-btn">
                  <FiPlus size={20} />
                  <span>Adicionar Seção</span>
                  {showAddPanel ? <FiChevronUp size={16} /> : <FiChevronDown size={16} />}
                </button>

                {showAddPanel && (
                  <div className="pb-add-panel">
                    {SECTION_TYPES.map(st => (
                      <button key={st.type} className="pb-add-type" onClick={() => addSection(st.type)}>
                        <div className="pb-add-type__icon" style={{ background: st.color }}>
                          <st.icon size={16} />
                        </div>
                        <div>
                          <strong>{st.label}</strong>
                          <span>{st.desc}</span>
                        </div>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {/* Preview */}
        {selectedPage && showPreview && (
          <div className="pb-preview">
            <div className="pb-preview__frame">
              <iframe
                src={selectedPage.slug === 'home' ? '/' : `/${selectedPage.slug}`}
                title="Preview"
                style={{ width: '100%', height: '100%', border: 'none' }}
              />
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
