import React, { useState, useEffect, useCallback } from 'react';
import { toast } from 'react-toastify';
import { FiPlus, FiTrash2, FiEdit3, FiX, FiCheck } from 'react-icons/fi';
import { servicesAPI } from '../api/api';
import MediaPicker from './MediaPicker';

export default function ServicesManager() {
  const [services, setServices] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [editing, setEditing] = useState(null);
  const [showMediaPicker, setShowMediaPicker] = useState(false);
  const [form, setForm] = useState({ title: '', description: '', price_range: '', image_url: '', is_active: 1, features: [] });
  const [newFeature, setNewFeature] = useState('');

  const load = useCallback(async () => {
    setLoading(true);
    try { const res = await servicesAPI.getAll(); setServices(res.data.data || []); }
    catch { toast.error('Erro ao carregar serviços'); }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { load(); }, [load]);

  const openForm = (svc = null) => {
    if (svc) {
      setEditing(svc.id);
      setForm({
        title: svc.title || '', description: svc.description || '', price_range: svc.price_range || '',
        image_url: svc.image_url || '', is_active: svc.is_active ?? 1,
        features: svc.features ? (typeof svc.features === 'string' ? JSON.parse(svc.features) : svc.features) : []
      });
    } else {
      setEditing(null);
      setForm({ title: '', description: '', price_range: '', image_url: '', is_active: 1, features: [] });
    }
    setShowForm(true);
  };

  const save = async () => {
    if (!form.title.trim()) { toast.warning('Título obrigatório'); return; }
    try {
      const data = { ...form, features: JSON.stringify(form.features) };
      if (editing) { await servicesAPI.update(editing, data); toast.success('Serviço atualizado!'); }
      else { await servicesAPI.create(data); toast.success('Serviço criado!'); }
      setShowForm(false);
      load();
    } catch { toast.error('Erro ao salvar'); }
  };

  const remove = async (id) => {
    if (!window.confirm('Excluir este serviço?')) return;
    try { await servicesAPI.delete(id); toast.success('Excluído!'); load(); }
    catch { toast.error('Erro ao excluir'); }
  };

  const addFeature = () => {
    if (!newFeature.trim()) return;
    setForm(f => ({ ...f, features: [...f.features, newFeature.trim()] }));
    setNewFeature('');
  };

  const removeFeature = (idx) => {
    setForm(f => ({ ...f, features: f.features.filter((_, i) => i !== idx) }));
  };

  return (
    <div>
      <div className="admin-page-header">
        <h1>Serviços</h1>
        <button onClick={() => openForm()} className="admin-btn admin-btn--primary"><FiPlus size={16} /> Novo Serviço</button>
      </div>

      {loading ? <div className="admin-card" style={{ textAlign: 'center', padding: 40, color: '#888' }}>Carregando...</div> : (
        <div className="admin-card">
          <table className="admin-table">
            <thead><tr><th>Título</th><th>Faixa de preço</th><th>Recursos</th><th>Status</th><th>Ações</th></tr></thead>
            <tbody>
              {services.map(s => {
                const features = s.features ? (typeof s.features === 'string' ? JSON.parse(s.features) : s.features) : [];
                return (
                  <tr key={s.id}>
                    <td><strong>{s.title}</strong></td>
                    <td style={{ color: '#c9a96e' }}>{s.price_range || '-'}</td>
                    <td style={{ color: '#aaa' }}>{features.length} itens</td>
                    <td><span className={`admin-badge ${s.is_active ? 'admin-badge--success' : 'admin-badge--warning'}`}>{s.is_active ? 'Ativo' : 'Inativo'}</span></td>
                    <td>
                      <div style={{ display: 'flex', gap: 4 }}>
                        <button onClick={() => openForm(s)} className="admin-btn admin-btn--secondary admin-btn--small"><FiEdit3 size={12} /></button>
                        <button onClick={() => remove(s.id)} className="admin-btn admin-btn--danger admin-btn--small"><FiTrash2 size={12} /></button>
                      </div>
                    </td>
                  </tr>
                );
              })}
              {services.length === 0 && <tr><td colSpan={5} style={{ textAlign: 'center', color: '#888', padding: 30 }}>Nenhum serviço ainda.</td></tr>}
            </tbody>
          </table>
        </div>
      )}

      {showForm && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.7)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }}
          onClick={e => e.target === e.currentTarget && setShowForm(false)}>
          <div className="admin-card" style={{ width: 500, maxHeight: '85vh', overflowY: 'auto' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
              <h3 style={{ color: '#fff', margin: 0 }}>{editing ? 'Editar Serviço' : 'Novo Serviço'}</h3>
              <button onClick={() => setShowForm(false)} style={{ background: 'none', border: 'none', color: '#888', cursor: 'pointer' }}><FiX size={18} /></button>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              <div>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Título *</label>
                <input value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} className="admin-input" />
              </div>
              <div>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Descrição</label>
                <textarea value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} className="admin-input" rows={4} />
              </div>
              <div>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Faixa de preço</label>
                <input value={form.price_range} onChange={e => setForm(f => ({ ...f, price_range: e.target.value }))} className="admin-input" placeholder="A partir de R$ 5.000" />
              </div>
              <div>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Imagem</label>
                <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                  {form.image_url && <img src={form.image_url} alt="" style={{ width: 60, height: 40, objectFit: 'cover', borderRadius: 4 }} />}
                  <button onClick={() => setShowMediaPicker(true)} className="admin-btn admin-btn--secondary admin-btn--small">Selecionar</button>
                  {form.image_url && <button onClick={() => setForm(f => ({ ...f, image_url: '' }))} className="admin-btn admin-btn--danger admin-btn--small"><FiTrash2 size={12} /></button>}
                </div>
              </div>

              {/* Features */}
              <div>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>O que inclui</label>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, marginBottom: 8 }}>
                  {form.features.map((f, idx) => (
                    <span key={idx} style={{ background: '#1a1a2e', border: '1px solid #2a2a3e', borderRadius: 20, padding: '4px 10px', fontSize: 12, color: '#ccc', display: 'flex', alignItems: 'center', gap: 4 }}>
                      {f} <button onClick={() => removeFeature(idx)} style={{ background: 'none', border: 'none', color: '#e74c3c', cursor: 'pointer', padding: 0, fontSize: 14 }}>×</button>
                    </span>
                  ))}
                </div>
                <div style={{ display: 'flex', gap: 6 }}>
                  <input value={newFeature} onChange={e => setNewFeature(e.target.value)} onKeyDown={e => e.key === 'Enter' && (e.preventDefault(), addFeature())} className="admin-input" placeholder="Ex: Filme completo 4K" style={{ flex: 1 }} />
                  <button onClick={addFeature} className="admin-btn admin-btn--secondary admin-btn--small"><FiPlus size={12} /></button>
                </div>
              </div>

              <label style={{ display: 'flex', alignItems: 'center', gap: 6, color: '#ccc', fontSize: 13, cursor: 'pointer' }}>
                <input type="checkbox" checked={!!form.is_active} onChange={e => setForm(f => ({ ...f, is_active: e.target.checked ? 1 : 0 }))} style={{ accentColor: '#c9a96e' }} /> Ativo
              </label>
            </div>

            <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 20 }}>
              <button onClick={() => setShowForm(false)} className="admin-btn admin-btn--secondary">Cancelar</button>
              <button onClick={save} className="admin-btn admin-btn--primary"><FiCheck size={14} /> {editing ? 'Salvar' : 'Criar'}</button>
            </div>
          </div>
        </div>
      )}

      {showMediaPicker && (
        <MediaPicker type="image" onSelect={(url) => { setForm(f => ({ ...f, image_url: url })); setShowMediaPicker(false); }} onClose={() => setShowMediaPicker(false)} />
      )}
    </div>
  );
}
