import React, { useState, useEffect, useCallback } from 'react';
import { toast } from 'react-toastify';
import { FiPlus, FiTrash2, FiEdit3, FiX, FiCheck, FiStar, FiMessageSquare } from 'react-icons/fi';
import { testimonialsAPI, projectsAPI } from '../api/api';

export default function TestimonialsManager() {
  const [testimonials, setTestimonials] = useState([]);
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState({ couple_names: '', quote: '', rating: 5, project_id: '', is_featured: 0, is_active: 1 });

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const [tRes, pRes] = await Promise.all([testimonialsAPI.getAll(), projectsAPI.getAll()]);
      setTestimonials(tRes.data.data || []);
      setProjects(pRes.data.data || []);
    } catch { toast.error('Erro ao carregar depoimentos'); }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { load(); }, [load]);

  const openForm = (t = null) => {
    if (t) {
      setEditing(t.id);
      setForm({ couple_names: t.couple_names || '', quote: t.quote || '', rating: t.rating || 5, project_id: t.project_id || '', is_featured: t.is_featured || 0, is_active: t.is_active ?? 1 });
    } else {
      setEditing(null);
      setForm({ couple_names: '', quote: '', rating: 5, project_id: '', is_featured: 0, is_active: 1 });
    }
    setShowForm(true);
  };

  const save = async () => {
    if (!form.couple_names.trim() || !form.quote.trim()) { toast.warning('Nome e citação são obrigatórios'); return; }
    try {
      if (editing) { await testimonialsAPI.update(editing, form); toast.success('Depoimento atualizado!'); }
      else { await testimonialsAPI.create(form); toast.success('Depoimento criado!'); }
      setShowForm(false);
      load();
    } catch { toast.error('Erro ao salvar'); }
  };

  const remove = async (id) => {
    if (!window.confirm('Excluir este depoimento?')) return;
    try { await testimonialsAPI.delete(id); toast.success('Excluído!'); load(); }
    catch { toast.error('Erro ao excluir'); }
  };

  const renderStars = (rating) => {
    return Array.from({ length: 5 }, (_, i) => (
      <FiStar key={i} size={12} style={{ color: i < rating ? '#c9a96e' : '#333', fill: i < rating ? '#c9a96e' : 'none' }} />
    ));
  };

  return (
    <div>
      <div className="admin-page-header">
        <h1>Depoimentos</h1>
        <button onClick={() => openForm()} className="admin-btn admin-btn--primary"><FiPlus size={16} /> Novo Depoimento</button>
      </div>

      {loading ? <div className="admin-card" style={{ textAlign: 'center', padding: 40, color: '#888' }}>Carregando...</div> : (
        <div className="admin-card">
          <table className="admin-table">
            <thead><tr><th>Casal</th><th>Citação</th><th>Avaliação</th><th>Destaque</th><th>Status</th><th>Ações</th></tr></thead>
            <tbody>
              {testimonials.map(t => (
                <tr key={t.id}>
                  <td><strong>{t.couple_names}</strong></td>
                  <td style={{ color: '#aaa', maxWidth: 300, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{t.quote}</td>
                  <td><div style={{ display: 'flex', gap: 2 }}>{renderStars(t.rating)}</div></td>
                  <td>{t.is_featured ? <FiStar size={14} color="#c9a96e" /> : '-'}</td>
                  <td><span className={`admin-badge ${t.is_active ? 'admin-badge--success' : 'admin-badge--warning'}`}>{t.is_active ? 'Ativo' : 'Oculto'}</span></td>
                  <td>
                    <div style={{ display: 'flex', gap: 4 }}>
                      <button onClick={() => openForm(t)} className="admin-btn admin-btn--secondary admin-btn--small"><FiEdit3 size={12} /></button>
                      <button onClick={() => remove(t.id)} className="admin-btn admin-btn--danger admin-btn--small"><FiTrash2 size={12} /></button>
                    </div>
                  </td>
                </tr>
              ))}
              {testimonials.length === 0 && <tr><td colSpan={6} style={{ textAlign: 'center', color: '#888', padding: 30 }}>Nenhum depoimento ainda.</td></tr>}
            </tbody>
          </table>
        </div>
      )}

      {showForm && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.7)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }}
          onClick={e => e.target === e.currentTarget && setShowForm(false)}>
          <div className="admin-card" style={{ width: 500, maxHeight: '85vh', overflowY: 'auto' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
              <h3 style={{ color: '#fff', margin: 0 }}><FiMessageSquare size={16} style={{ marginRight: 8 }} />{editing ? 'Editar Depoimento' : 'Novo Depoimento'}</h3>
              <button onClick={() => setShowForm(false)} style={{ background: 'none', border: 'none', color: '#888', cursor: 'pointer' }}><FiX size={18} /></button>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              <div>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Nomes do casal *</label>
                <input value={form.couple_names} onChange={e => setForm(f => ({ ...f, couple_names: e.target.value }))} className="admin-input" placeholder="Maria & João" />
              </div>
              <div>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Citação *</label>
                <textarea value={form.quote} onChange={e => setForm(f => ({ ...f, quote: e.target.value }))} className="admin-input" rows={5} placeholder="O que o casal disse sobre o seu trabalho..." />
              </div>
              <div>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Avaliação</label>
                <div style={{ display: 'flex', gap: 4 }}>
                  {[1,2,3,4,5].map(n => (
                    <button key={n} onClick={() => setForm(f => ({ ...f, rating: n }))}
                      style={{ background: 'none', border: 'none', cursor: 'pointer', padding: 4 }}>
                      <FiStar size={20} style={{ color: n <= form.rating ? '#c9a96e' : '#333', fill: n <= form.rating ? '#c9a96e' : 'none' }} />
                    </button>
                  ))}
                </div>
              </div>
              <div>
                <label style={{ fontSize: 12, color: '#aaa', display: 'block', marginBottom: 4 }}>Projeto relacionado</label>
                <select value={form.project_id} onChange={e => setForm(f => ({ ...f, project_id: e.target.value }))} className="admin-input">
                  <option value="">Nenhum</option>
                  {projects.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                </select>
              </div>
              <div style={{ display: 'flex', gap: 16 }}>
                <label style={{ display: 'flex', alignItems: 'center', gap: 6, color: '#ccc', fontSize: 13, cursor: 'pointer' }}>
                  <input type="checkbox" checked={!!form.is_featured} onChange={e => setForm(f => ({ ...f, is_featured: e.target.checked ? 1 : 0 }))} style={{ accentColor: '#c9a96e' }} /> Destaque
                </label>
                <label style={{ display: 'flex', alignItems: 'center', gap: 6, color: '#ccc', fontSize: 13, cursor: 'pointer' }}>
                  <input type="checkbox" checked={!!form.is_active} onChange={e => setForm(f => ({ ...f, is_active: e.target.checked ? 1 : 0 }))} style={{ accentColor: '#c9a96e' }} /> Ativo
                </label>
              </div>
            </div>

            <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 20 }}>
              <button onClick={() => setShowForm(false)} className="admin-btn admin-btn--secondary">Cancelar</button>
              <button onClick={save} className="admin-btn admin-btn--primary"><FiCheck size={14} /> {editing ? 'Salvar' : 'Criar'}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
