import React, { useState, useEffect, useCallback } from 'react';
import { toast } from 'react-toastify';
import { FiMail, FiTrash2, FiEye, FiX, FiCheck, FiClock, FiMapPin, FiUser } from 'react-icons/fi';
import { contactAPI } from '../api/api';

export default function ContactSubmissions() {
  const [submissions, setSubmissions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [pagination, setPagination] = useState({});
  const [page, setPage] = useState(1);
  const [selected, setSelected] = useState(null);
  const [unreadCount, setUnreadCount] = useState(0);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await contactAPI.getAll({ page, per_page: 20 });
      setSubmissions(res.data.data || []);
      setPagination(res.data.pagination || {});
      setUnreadCount(res.data.unread_count || 0);
    } catch { toast.error('Erro ao carregar mensagens'); }
    finally { setLoading(false); }
  }, [page]);

  useEffect(() => { load(); }, [load]);

  const viewSubmission = async (sub) => {
    setSelected(sub);
    if (!sub.is_read) {
      try {
        await contactAPI.markRead(sub.id);
        setSubmissions(prev => prev.map(s => s.id === sub.id ? { ...s, is_read: 1 } : s));
        setUnreadCount(prev => Math.max(0, prev - 1));
      } catch {}
    }
  };

  const remove = async (id) => {
    if (!window.confirm('Excluir esta mensagem?')) return;
    try {
      await contactAPI.delete(id);
      toast.success('Mensagem excluída!');
      if (selected?.id === id) setSelected(null);
      load();
    } catch { toast.error('Erro ao excluir'); }
  };

  const formatDate = (dateStr) => {
    if (!dateStr) return '';
    return new Date(dateStr).toLocaleString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });
  };

  const parseData = (sub) => {
    try { return typeof sub.form_data === 'string' ? JSON.parse(sub.form_data) : (sub.form_data || {}); }
    catch { return {}; }
  };

  return (
    <div>
      <div className="admin-page-header">
        <h1>Mensagens de Contato {unreadCount > 0 && <span className="admin-badge admin-badge--danger" style={{ marginLeft: 8 }}>{unreadCount} não lidas</span>}</h1>
      </div>

      {loading ? (
        <div className="admin-card" style={{ textAlign: 'center', padding: 40, color: '#888' }}>Carregando...</div>
      ) : (
        <div className="admin-card">
          <table className="admin-table">
            <thead><tr><th></th><th>Nome</th><th>E-mail</th><th>Tipo</th><th>Data</th><th>Ações</th></tr></thead>
            <tbody>
              {submissions.map(sub => (
                <tr key={sub.id} style={{ fontWeight: sub.is_read ? 'normal' : 'bold', cursor: 'pointer' }} onClick={() => viewSubmission(sub)}>
                  <td style={{ width: 30 }}>
                    {!sub.is_read && <div style={{ width: 8, height: 8, borderRadius: '50%', background: '#c9a96e' }} />}
                  </td>
                  <td>{sub.name}</td>
                  <td style={{ color: '#aaa' }}>{sub.email}</td>
                  <td><span className="admin-badge">{sub.contact_type || 'geral'}</span></td>
                  <td style={{ color: '#aaa', fontSize: 12 }}>{formatDate(sub.created_at)}</td>
                  <td>
                    <div style={{ display: 'flex', gap: 4 }} onClick={e => e.stopPropagation()}>
                      <button onClick={() => viewSubmission(sub)} className="admin-btn admin-btn--secondary admin-btn--small"><FiEye size={12} /></button>
                      <button onClick={() => remove(sub.id)} className="admin-btn admin-btn--danger admin-btn--small"><FiTrash2 size={12} /></button>
                    </div>
                  </td>
                </tr>
              ))}
              {submissions.length === 0 && <tr><td colSpan={6} style={{ textAlign: 'center', color: '#888', padding: 30 }}>Nenhuma mensagem recebida.</td></tr>}
            </tbody>
          </table>
        </div>
      )}

      {pagination.total_pages > 1 && (
        <div style={{ display: 'flex', justifyContent: 'center', gap: 12, padding: 16, alignItems: 'center' }}>
          <button disabled={page <= 1} onClick={() => setPage(p => p - 1)} className="admin-btn admin-btn--secondary admin-btn--small">Anterior</button>
          <span style={{ color: '#888', fontSize: 13 }}>Página {page} de {pagination.total_pages}</span>
          <button disabled={page >= pagination.total_pages} onClick={() => setPage(p => p + 1)} className="admin-btn admin-btn--secondary admin-btn--small">Próxima</button>
        </div>
      )}

      {/* Detail Modal */}
      {selected && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.7)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }}
          onClick={e => e.target === e.currentTarget && setSelected(null)}>
          <div className="admin-card" style={{ width: 540, maxHeight: '80vh', overflowY: 'auto' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
              <h3 style={{ color: '#fff', margin: 0 }}><FiMail size={16} style={{ marginRight: 8 }} />Mensagem</h3>
              <button onClick={() => setSelected(null)} style={{ background: 'none', border: 'none', color: '#888', cursor: 'pointer' }}><FiX size={18} /></button>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              <div style={{ display: 'flex', gap: 20, flexWrap: 'wrap' }}>
                <div>
                  <label style={{ fontSize: 11, color: '#888', textTransform: 'uppercase' }}>Nome</label>
                  <p style={{ color: '#fff', margin: '4px 0 0' }}>{selected.name}</p>
                </div>
                <div>
                  <label style={{ fontSize: 11, color: '#888', textTransform: 'uppercase' }}>E-mail</label>
                  <p style={{ color: '#c9a96e', margin: '4px 0 0' }}><a href={`mailto:${selected.email}`} style={{ color: 'inherit' }}>{selected.email}</a></p>
                </div>
                {selected.phone && (
                  <div>
                    <label style={{ fontSize: 11, color: '#888', textTransform: 'uppercase' }}>Telefone</label>
                    <p style={{ color: '#ccc', margin: '4px 0 0' }}>{selected.phone}</p>
                  </div>
                )}
              </div>

              <div style={{ display: 'flex', gap: 8 }}>
                <span className="admin-badge">{selected.contact_type || 'geral'}</span>
                <span style={{ color: '#888', fontSize: 12, display: 'flex', alignItems: 'center', gap: 4 }}><FiClock size={12} /> {formatDate(selected.created_at)}</span>
              </div>

              {selected.message && (
                <div style={{ background: '#12121e', borderRadius: 8, padding: 16, marginTop: 8 }}>
                  <label style={{ fontSize: 11, color: '#888', textTransform: 'uppercase', marginBottom: 8, display: 'block' }}>Mensagem</label>
                  <p style={{ color: '#ccc', margin: 0, lineHeight: 1.6, whiteSpace: 'pre-wrap' }}>{selected.message}</p>
                </div>
              )}

              {/* Additional form data */}
              {(() => {
                const data = parseData(selected);
                const keys = Object.keys(data);
                if (keys.length === 0) return null;
                return (
                  <div style={{ background: '#12121e', borderRadius: 8, padding: 16 }}>
                    <label style={{ fontSize: 11, color: '#888', textTransform: 'uppercase', marginBottom: 8, display: 'block' }}>Dados adicionais</label>
                    {keys.map(key => (
                      <div key={key} style={{ marginBottom: 8 }}>
                        <strong style={{ color: '#aaa', fontSize: 12 }}>{key}: </strong>
                        <span style={{ color: '#ccc', fontSize: 13 }}>{String(data[key])}</span>
                      </div>
                    ))}
                  </div>
                );
              })()}
            </div>

            <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 20 }}>
              <button onClick={() => remove(selected.id)} className="admin-btn admin-btn--danger"><FiTrash2 size={14} /> Excluir</button>
              <button onClick={() => setSelected(null)} className="admin-btn admin-btn--secondary">Fechar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
