import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { FiMenu, FiX, FiInstagram } from 'react-icons/fi';
import { useSite } from '../contexts/SiteContext';
import './Navbar.css';

const DEFAULT_LINKS = [
  { id: 'home', title: 'Início', url: '/' },
  { id: 'projects', title: 'Projetos', url: '/projects' },
  { id: 'services', title: 'Serviços', url: '/services' },
  { id: 'about', title: 'Sobre Nós', url: '/about' },
  { id: 'contact', title: 'Contato', url: '/contact' },
];

export default function Navbar() {
  const { menuItems, getSetting } = useSite();
  const [scrolled, setScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const location = useLocation();

  const siteLogo = getSetting('site_logo');
  const siteName = getSetting('site_name', 'STORNOWAY');
  const instagram = getSetting('instagram_url');

  const links = menuItems.length > 0 ? menuItems : DEFAULT_LINKS;

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    setMobileOpen(false);
  }, [location]);

  return (
    <nav className={`navbar ${scrolled ? 'navbar--scrolled' : ''}`}>
      <div className="navbar__inner">
        <Link to="/" className="navbar__logo">
          {siteLogo ? (
            <img src={siteLogo} alt={siteName} />
          ) : (
            <span className="navbar__logo-text">{siteName}</span>
          )}
        </Link>

        <div className="navbar__links">
          {links.map(item => (
            <Link
              key={item.id}
              to={item.url}
              className={`navbar__link ${location.pathname === item.url ? 'navbar__link--active' : ''}`}
              target={item.open_new_tab ? '_blank' : undefined}
              rel={item.open_new_tab ? 'noopener noreferrer' : undefined}
            >
              {item.title.toUpperCase()}
            </Link>
          ))}
        </div>

        <div className="navbar__right">
          {instagram && (
            <a href={instagram} target="_blank" rel="noopener noreferrer" className="navbar__social">
              <FiInstagram size={20} />
            </a>
          )}
          <button className="navbar__mobile-toggle" onClick={() => setMobileOpen(!mobileOpen)} aria-label="Menu">
            {mobileOpen ? <FiX size={24} /> : <FiMenu size={24} />}
          </button>
        </div>
      </div>

      <AnimatePresence>
        {mobileOpen && (
          <motion.div
            className="navbar__mobile"
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            transition={{ duration: 0.3 }}
          >
            {links.map(item => (
              <Link key={item.id} to={item.url} className="navbar__mobile-link">
                {item.title.toUpperCase()}
              </Link>
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
}
