import React, { createContext, useContext, useState, useEffect } from 'react';
import { settingsAPI, menuAPI } from '../api/api';

const SiteContext = createContext();

export function SiteProvider({ children }) {
  const [settings, setSettings] = useState({});
  const [menuItems, setMenuItems] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      settingsAPI.getAll().catch(() => ({ data: { data: {} } })),
      menuAPI.getAll().catch(() => ({ data: { data: [] } }))
    ]).then(([settingsRes, menuRes]) => {
      const s = {};
      const raw = settingsRes.data.data;
      Object.keys(raw).forEach(key => {
        s[key] = raw[key].value !== undefined ? raw[key].value : raw[key];
      });
      setSettings(s);
      setMenuItems(menuRes.data.data || []);
    }).finally(() => setLoading(false));
  }, []);

  const getSetting = (key, fallback = '') => settings[key] || fallback;

  const refreshSettings = async () => {
    const res = await settingsAPI.getAll();
    const s = {};
    const raw = res.data.data;
    Object.keys(raw).forEach(key => {
      s[key] = raw[key].value !== undefined ? raw[key].value : raw[key];
    });
    setSettings(s);
  };

  const refreshMenu = async () => {
    const res = await menuAPI.getAll();
    setMenuItems(res.data.data || []);
  };

  return (
    <SiteContext.Provider value={{ settings, menuItems, loading, getSetting, refreshSettings, refreshMenu }}>
      {children}
    </SiteContext.Provider>
  );
}

export const useSite = () => useContext(SiteContext);
